def calc_athletic_bonus(row, bucket):
    spd = safe_num(row.get("SPD", 0))
    acc = safe_num(row.get("ACC", 0))
    agi = safe_num(row.get("AGI", 0))
    cod = safe_num(row.get("COD", 0))
    awr = safe_num(row.get("AWR", 0))
    strength = safe_num(row.get("STR", 0))

    if bucket in {"WR", "CB", "RB", "S"}:
        return (spd + acc + agi + cod) / 20.0
    if bucket == "QB":
        return (awr + acc + agi) / 15.0
    if bucket in {"OL", "IDL", "EDGE", "LB"}:
        return (strength + acc + awr) / 15.0
    if bucket == "TE":
        return (spd + strength + acc) / 18.0
    return (spd + acc + awr) / 18.0


def calc_draft_value(row):
    bucket = clean_bucket(row.get("PosBucket", row.get("Pos", "")))
    ovr = safe_num(row.get("OVR", 0))
    awr = safe_num(row.get("AWR", 0))
    player_class = str(row.get("Class", "")).strip()

    class_bonus = {
        "JR": 2.5,
        "JR (RS)": 1.5,
        "SR": 1.0,
        "SR (RS)": 0.5,
    }.get(player_class, 0.0)

    athletic_bonus = calc_athletic_bonus(row, bucket)
    pos_bonus = POS_PREMIUM.get(bucket, 3)
    variance = random.uniform(-2.5, 2.5)

    return round((ovr * 0.70) + (awr * 0.08) + athletic_bonus + pos_bonus + class_bonus + variance, 2)


def derive_cpu_draft_from_top20(year=None, write_csv=True):
    """
    Build cpu_draft_pool.csv candidates from cfb_136_top30_rosters_{YEAR}.csv.

    Filters to SR / SR (RS) players (draft-eligible seniors), derives PosBucket,
    calculates DraftValueScore, assigns provisional DraftRound, and outputs a
    DataFrame schema-compatible with cpu_draft_pool.csv.

    Call this after the 272-screenshot TOP20_ROSTERS batch is complete.
    Existing cpu_draft_pool entries are preserved; only new players are appended.
    Returns the derived DataFrame (not the merged one).
    """
    target_year = int(year) if year else CURRENT_YEAR
    roster_file = f'cfb_136_top30_rosters_{target_year}.csv'

    if not os.path.exists(roster_file):
        return pd.DataFrame()

    try:
        df = pd.read_csv(roster_file)
    except Exception:
        return pd.DataFrame()

    # Normalize columns
    df.columns = [str(c).strip() for c in df.columns]
    df['YEAR_CLASS'] = df.get('YEAR_CLASS', df.get('Class', '')).astype(str).str.strip()

    # Normalize TEAM column — same map as compute_ms_plus
    if 'TEAM' in df.columns:
        _team_norm = {
            'University of Nevada, Las Vegas': 'UNLV',
            'University of South Florida':     'USF',
            'University of Southern California': 'USC',
            'University of Texas at San Antonio': 'UTSA',
            'University of Massachusetts':     'Massachusetts',
            'Southern Methodist':              'SMU',
            'Brigham Young':                   'BYU',
            'Pittsburgh Panthers':             'Pittsburgh',
            'Alabaster Bulldogs':              'Alabaster',
            'Hammond Carnivores':              'Hammond',
            'Rapid City Stegos':               'Rapid City',
        }
        df['TEAM'] = df['TEAM'].map(lambda t: _team_norm.get(str(t).strip(), str(t).strip()))
        # Dedup on TEAM+NAME+POS keeping highest OVR
        _oc = 'OVR' if 'OVR' in df.columns else None
        if _oc:
            df = df.sort_values(_oc, ascending=False)
        _nc = 'NAME' if 'NAME' in df.columns else ('Name' if 'Name' in df.columns else None)
        _pc = 'POS'  if 'POS'  in df.columns else ('Pos'  if 'Pos'  in df.columns else None)
        if _nc and _pc:
            df = df.drop_duplicates(subset=['TEAM', _nc, _pc], keep='first').reset_index(drop=True)

    # Filter to draft-eligible seniors only
    _sr_classes = {'SR', 'SR (RS)', 'SR(RS)'}
    draft_df = df[df['YEAR_CLASS'].str.upper().isin({c.upper() for c in _sr_classes})].copy()
    if draft_df.empty:
        return pd.DataFrame()

    # Coerce numeric stat columns
    _stat_cols = ['OVR','SPD','ACC','AGI','COD','STR','AWR',
                  'THP','THV','THA','THS','TRL','ELU','CAR',
                  'CTH','SPC','RLS','MCV','ZCV','PRC','TAK',
                  'POW','BKB','BLK','PBK','RBK']
    for c in _stat_cols:
        if c in draft_df.columns:
            draft_df[c] = pd.to_numeric(draft_df[c], errors='coerce').fillna(0).astype(int)

    # Derive PosBucket from POS
    draft_df['PosBucket'] = draft_df['POS'].apply(
        lambda p: clean_bucket(str(p).strip().upper())
    )

    # Build draft value score
    draft_df['DraftValueScore'] = draft_df.apply(
        lambda r: calc_draft_value({
            **r.to_dict(),
            'Class': r['YEAR_CLASS'],
            'PosBucket': r['PosBucket'],
        }), axis=1
    )

    # Assign provisional draft round based on DraftValueScore
    def _round(score):
        if score >= 103: return 1
        if score >= 97:  return 2
        if score >= 91:  return 3
        if score >= 85:  return 4
        if score >= 79:  return 5
        if score >= 73:  return 6
        return 7

    draft_df['DraftRound'] = draft_df['DraftValueScore'].apply(_round)
    draft_df = draft_df.sort_values('DraftValueScore', ascending=False).reset_index(drop=True)
    draft_df['DraftRank'] = draft_df.index + 1

    # Build output in cpu_draft_pool schema
    out = pd.DataFrame({
        'DraftYear':       target_year,
        'DraftRank':       draft_df['DraftRank'],
        'Player':          draft_df['NAME'],
        'CollegeTeam':     draft_df['TEAM'],
        'Pos':             draft_df['POS'],
        'PosBucket':       draft_df['PosBucket'],
        'Class':           draft_df['YEAR_CLASS'],
        'OVR':             draft_df.get('OVR', 0),
        'SPD':             draft_df.get('SPD', 0),
        'ACC':             draft_df.get('ACC', 0),
        'AGI':             draft_df.get('AGI', 0),
        'COD':             draft_df.get('COD', 0),
        'STR':             draft_df.get('STR', 0),
        'AWR':             draft_df.get('AWR', 0),
        'DraftValueScore': draft_df['DraftValueScore'],
        'DraftRound':      draft_df['DraftRound'],
    })

    if write_csv:
        pool_file = 'cpu_draft_pool.csv'
        try:
            if os.path.exists(pool_file):
                existing = pd.read_csv(pool_file)
                existing['DraftYear'] = pd.to_numeric(existing.get('DraftYear', 0), errors='coerce')
                # Remove any prior auto-derived entries for this year, keep manual/watcher entries
                existing = existing[
                    ~((existing['DraftYear'].fillna(-1).astype(int) == target_year) &
                      (existing.get('Source', pd.Series([''] * len(existing))).astype(str).str.upper() == 'TOP20_DERIVED'))
                ]
                out['Source'] = 'TOP20_DERIVED'
                combined = pd.concat([existing, out], ignore_index=True)
                combined.to_csv(pool_file, index=False)
            else:
                out['Source'] = 'TOP20_DERIVED'
                out.to_csv(pool_file, index=False)
        except Exception:
            pass

    return out


def build_nfl_team_needs(nfl_roster_df):
    if nfl_roster_df is None or nfl_roster_df.empty:
        return pd.DataFrame(columns=[
            "NFLTeam", "PosBucket", "NeedScore", "StarterOVR", "StarterAge", "DepthCount"
        ])

    df = nfl_roster_df.copy()

    if "Team" not in df.columns:
        df["Team"] = ""
    if "Pos" not in df.columns:
        df["Pos"] = ""
    if "OVR" not in df.columns:
        df["OVR"] = 70
    if "Age" not in df.columns:
        df["Age"] = 25

    df["Team"] = df["Team"].fillna("").astype(str).str.strip()
    df["Pos"] = df["Pos"].fillna("").astype(str).str.strip()
    df["OVR"] = pd.to_numeric(df["OVR"], errors="coerce").fillna(70)
    df["Age"] = pd.to_numeric(df["Age"], errors="coerce").fillna(25)
    df["PosBucket"] = df["Pos"].map(clean_bucket)

    room_targets = {
        "QB": 3,
        "RB": 4,
        "WR": 6,
        "TE": 3,
        "OL": 9,
        "EDGE": 4,
        "IDL": 4,
        "LB": 5,
        "CB": 5,
        "S": 4
    }

    starter_counts = {
        "QB": 1,
        "RB": 1,
        "WR": 3,
        "TE": 1,
        "OL": 5,
        "EDGE": 2,
        "IDL": 2,
        "LB": 3,
        "CB": 2,
        "S": 2
    }

    premium_weight = {
        "QB": 1.55,
        "OL": 1.20,
        "EDGE": 1.18,
        "CB": 1.12,
        "WR": 1.10,
        "LT": 1.15,
        "S": 1.00,
        "RB": 0.95,
        "TE": 0.95,
        "IDL": 1.00,
        "LB": 0.98
    }

    rows = []

    for team in sorted(df["Team"].dropna().astype(str).unique().tolist()):
        team_df = df[df["Team"].astype(str) == str(team)].copy()

        for bucket, room_target in room_targets.items():
            room = team_df[team_df["PosBucket"].astype(str) == str(bucket)].copy()
            room = room.sort_values(["OVR", "Age"], ascending=[False, True]).reset_index(drop=True)

            starter_n = starter_counts.get(bucket, 1)

            starter_ovr = safe_num(room["OVR"].iloc[0], 68) if not room.empty else 68
            starter_age = safe_num(room["Age"].iloc[0], 25) if not room.empty else 25
            depth_count = int(len(room))

            top_starters = room.head(starter_n).copy()
            top_depth = room.head(min(room_target, len(room))).copy()

            starter_avg = safe_num(top_starters["OVR"].mean(), starter_ovr if not room.empty else 68)
            depth_avg = safe_num(top_depth["OVR"].mean(), starter_avg if not top_starters.empty else 68)

            need = 0.0

            if bucket == "QB":
                if starter_ovr <= 72:
                    need += 42
                elif starter_ovr <= 76:
                    need += 30
                elif starter_ovr <= 80:
                    need += 18
                elif starter_ovr <= 84:
                    need += 8

                if starter_ovr >= 95 and starter_age <= 31:
                    need -= 50
                elif starter_ovr >= 90 and starter_age <= 32:
                    need -= 40
                elif starter_ovr >= 85 and starter_age <= 30:
                    need -= 28
                elif starter_ovr >= 82 and starter_age <= 28:
                    need -= 18

            else:
                if starter_avg <= 70:
                    need += 26
                elif starter_avg <= 74:
                    need += 18
                elif starter_avg <= 78:
                    need += 10
                elif starter_avg <= 82:
                    need += 4

                if starter_age >= 32:
                    need += 5
                elif starter_age >= 30:
                    need += 2

                if starter_avg >= 90:
                    need -= 18
                elif starter_avg >= 86:
                    need -= 10

            missing_depth = max(0, room_target - depth_count)
            need += missing_depth * 4.5

            if depth_count > 0:
                if depth_avg <= 68:
                    need += 6
                elif depth_avg <= 72:
                    need += 3
                elif depth_avg >= 84:
                    need -= 4

            if depth_count >= room_target:
                if starter_avg >= 84 and depth_avg >= 78:
                    need -= 8
                if starter_avg >= 88 and depth_avg >= 80:
                    need -= 6

            need *= premium_weight.get(bucket, 1.0)
            need = round(max(0, min(99, need)), 2)

            rows.append({
                "NFLTeam": team,
                "PosBucket": bucket,
                "NeedScore": need,
                "StarterOVR": round(float(starter_ovr), 2),
                "StarterAge": round(float(starter_age), 2),
                "DepthCount": depth_count
            })

    out = pd.DataFrame(rows)
    if out.empty:
        return pd.DataFrame(columns=[
            "NFLTeam", "PosBucket", "NeedScore", "StarterOVR", "StarterAge", "DepthCount"
        ])

    out = out.sort_values(["NFLTeam", "NeedScore"], ascending=[True, False]).reset_index(drop=True)
    return out

def assign_career_tier(round_num):
    r = random.random()
    tables = {
        1: [("Superstar", 0.18), ("Star", 0.28), ("Solid Starter", 0.27), ("Starter", 0.17), ("Rotation", 0.07), ("Bust", 0.03)],
        2: [("Superstar", 0.08), ("Star", 0.20), ("Solid Starter", 0.30), ("Starter", 0.22), ("Rotation", 0.13), ("Bust", 0.07)],
        3: [("Superstar", 0.05), ("Star", 0.14), ("Solid Starter", 0.24), ("Starter", 0.26), ("Rotation", 0.20), ("Bust", 0.11)],
        4: [("Star", 0.03), ("Solid Starter", 0.12), ("Starter", 0.28), ("Rotation", 0.32), ("Fringe", 0.18), ("Bust", 0.07)],
        5: [("Star", 0.02), ("Solid Starter", 0.08), ("Starter", 0.20), ("Rotation", 0.35), ("Fringe", 0.25), ("Bust", 0.10)],
        6: [("Star", 0.01), ("Solid Starter", 0.05), ("Starter", 0.14), ("Rotation", 0.32), ("Fringe", 0.33), ("Bust", 0.15)],
        7: [("Star", 0.01), ("Solid Starter", 0.04), ("Starter", 0.10), ("Rotation", 0.25), ("Fringe", 0.38), ("Bust", 0.22)],
    }
    table = tables.get(int(round_num), tables[7])
    total = 0.0
    for label, p in table:
        total += p
        if r <= total:
            return label
    return table[-1][0]


def assign_rookie_role(round_num, need_score, pos_bucket):
    round_num = int(round_num)
    need_score = safe_num(need_score, 0)

    if pos_bucket == "QB":
        if round_num == 1 and need_score >= 80:
            return "QB Battle"
        if round_num <= 2:
            return "QB2"
        return "Developmental QB"

    if pos_bucket == "RB":
        if round_num <= 2 and need_score >= 70:
            return "Committee Back"
        if round_num <= 4:
            return "RB2"
        return "Depth Back"

    if pos_bucket == "WR":
        if round_num == 1 and need_score >= 80:
            return "Day 1 Starter"
        if round_num <= 2:
            return "WR3"
        return "Rotation WR"

    if pos_bucket == "TE":
        if round_num <= 3:
            return "TE2"
        return "Depth TE"

    if pos_bucket == "OL":
        if round_num <= 2 and need_score >= 75:
            return "Starter Battle"
        if round_num <= 4:
            return "Swing OL"
        return "Depth OL"

    if pos_bucket == "EDGE":
        if round_num <= 2:
            return "Pass Rush Rotation"
        return "Depth EDGE"

    if pos_bucket == "IDL":
        if round_num <= 3:
            return "DL Rotation"
        return "Depth IDL"

    if pos_bucket == "LB":
        if round_num <= 3:
            return "LB Rotation"
        return "Depth LB"

    if pos_bucket == "CB":
        if round_num <= 2:
            return "CB3"
        return "Depth CB"

    if pos_bucket == "S":
        if round_num <= 3:
            return "DB Rotation"
        return "Depth Safety"

    if round_num == 1 and need_score >= 80:
        return "Day 1 Starter"
    if round_num <= 2 and need_score >= 70:
        return "Primary Rotation"
    if round_num <= 4:
        return "Depth Piece"
    return "Roster Battle"


def estimate_peak_ovr(base_ovr, career_tier):
    base_ovr = int(round(safe_num(base_ovr, 70)))
    bumps = {
        "Superstar": random.randint(6, 10),
        "Star": random.randint(4, 7),
        "Solid Starter": random.randint(2, 5),
        "Starter": random.randint(1, 3),
        "Rotation": random.randint(0, 2),
        "Fringe": random.randint(-1, 1),
        "Bust": random.randint(-3, 0),
    }
    return max(60, min(99, base_ovr + bumps.get(career_tier, 0)))


def generate_story_tag(pos_bucket, career_tier, round_num):
    if career_tier == "Superstar":
        return "Face of the franchise"
    if career_tier == "Star" and int(round_num) >= 3:
        return "Mid-round steal"
    if career_tier == "Bust" and int(round_num) == 1:
        return "First-round pressure"
    if pos_bucket in {"WR", "CB"}:
        return "Speed mismatch"
    if pos_bucket == "EDGE":
        return "Pass-rush juice"
    if pos_bucket == "QB":
        return "Franchise swing"
    if pos_bucket == "RB":
        return "Explosive weapon"
    if pos_bucket == "OL":
        return "Trench anchor"
    return "Developmental upside"


