def normalize_conf_name(name):
    """Canonicalize conference names so the app always uses its internal labels."""
    s = str(name).strip()
    return CONF_NAME_ALIASES.get(s.lower(), s)

def build_sigmoid_natty_odds(year=None):
    """
    Per-team Championship & CFP odds.

    CFP%:  Rank-group lookup with record penalty. Gives intuitive spread:
           top-4 undefeated ~99%, top-12 with losses 60-85%, bad records <30%.
    Natty: Exponential decay by rank × loss multiplier × OVR fine-tune.
           C * exp(-0.15 * rank) * (0.60 ** losses) * ovr_mult
           #1 undefeated ~16%, #3 ~12%, #8 1-loss ~3%, 1-2 teams ~1%.

    No collision groups — each team evaluated independently.
    Returns dict: team_name → {'natty_pct': float, 'cfp_pct': float, 'raw': float}
    """
    if year is None:
        year = CURRENT_YEAR

    perf_map    = load_team_performance(year=year)
    ratings_map = load_team_ratings(year=year)

    cfp_rank_map = {}
    try:
        _rh = pd.read_csv('cfp_rankings_history.csv')
        _rh['YEAR'] = pd.to_numeric(_rh['YEAR'], errors='coerce')
        _rh['WEEK'] = pd.to_numeric(_rh['WEEK'], errors='coerce')
        _rh['RANK'] = pd.to_numeric(_rh['RANK'], errors='coerce')
        _cy = _rh[_rh['YEAR'] == int(year)]
        if not _cy.empty:
            _lw = _cy['WEEK'].max()
            for _, _r in _cy[_cy['WEEK'] == _lw].iterrows():
                _rk = int(_r['RANK']) if pd.notna(_r['RANK']) else 99
                if _rk > 0:
                    cfp_rank_map[str(_r['TEAM']).strip().lower()] = _rk
    except Exception:
        pass

    inj_penalty_map = {}
    try:
        _inj = pd.read_csv('injury_bulletin.csv')
        _inj['Year']     = pd.to_numeric(_inj.get('Year'),     errors='coerce')
        _inj['Week']     = pd.to_numeric(_inj.get('Week'),     errors='coerce').fillna(0)
        _inj['WeeksOut'] = pd.to_numeric(_inj.get('WeeksOut'), errors='coerce').fillna(0)
        _inj['OVR']      = pd.to_numeric(_inj.get('OVR'),      errors='coerce').fillna(75)
        _inj['_rem']     = (_inj['WeeksOut'] - (CURRENT_WEEK_NUMBER - _inj['Week'])).clip(lower=0)
        _inj = _inj[(_inj['Year'].fillna(-1).astype(int) == int(year)) & (_inj['_rem'] > 0)].copy()
        for _, _ir in _inj.iterrows():
            _tm  = str(_ir.get('Team', '')).strip().lower()
            _pos = str(_ir.get('Pos', '')).strip().upper()
            _ovr = float(_ir.get('OVR', 75))
            _wks = float(_ir.get('_rem', 0))
            if not _tm or _wks <= 0: continue
            _omult = max(0.1, min(1.0, (_ovr - 75) / 20.0))
            _base = (32.0 if _wks >= 8 else 16.0) if _pos == 'QB' else (6.0 if _wks >= 3 else 1.5)
            inj_penalty_map[_tm] = inj_penalty_map.get(_tm, 0.0) + _base * _omult
    except Exception:
        pass

    result = {}
    for team, perf in perf_map.items():
        try:
            w   = int(perf.get('W', 0) or 0)
            l   = int(perf.get('L', 0) or 0)
            gp  = w + l
            if gp == 0:
                continue

            _rl = team.strip().lower()
            _r  = (ratings_map.get(_rl)
                   or ratings_map.get(team.strip())
                   or next((v for k, v in ratings_map.items() if k.lower() == _rl), None)
                   or {})
            ovr = float(_r.get('OVR', _r.get('OVERALL', 82)) or 82) if _r else 82.0

            rank = cfp_rank_map.get(team.strip().lower())

            # ── CFP% ─────────────────────────────────────────────────────────
            # Rank-group baseline
            if rank is None:
                base_cfp = max(0.0, (w / max(gp, 1)) * 12.0)  # unranked: up to 12%
            elif rank <= 4:   base_cfp = 97.0
            elif rank <= 8:   base_cfp = 91.0
            elif rank <= 12:  base_cfp = 82.0
            elif rank <= 16:  base_cfp = 62.0
            elif rank <= 20:  base_cfp = 40.0
            else:             base_cfp = 22.0

            # Record penalty/bonus
            if l == 0:   rec_cfp = +5.0
            elif l == 1: rec_cfp = -8.0
            elif l == 2: rec_cfp = -20.0
            else:        rec_cfp = -32.0 - (l - 3) * 8.0

            # OVR fine-tune (small)
            ovr_cfp = (ovr - 82.0) * 0.25 if _r else 0.0

            cfp_pct = max(0.0, min(99.0, base_cfp + rec_cfp + ovr_cfp))

            # ── Natty% ───────────────────────────────────────────────────────
            # Exponential decay by rank, loss multiplier
            _rank_n = rank if (rank and rank <= 25) else 30
            natty_raw = 18.0 * np.exp(-0.15 * _rank_n) * (0.60 ** l)
            # OVR fine-tune
            if _r:
                natty_raw *= (1.0 + (ovr - 82.0) * 0.008)
            # Injury deduction
            natty_raw -= inj_penalty_map.get(team.strip().lower(), 0.0) * 0.20
            natty_pct = max(0.0, min(65.0, natty_raw))

            result[team] = {
                'natty_pct': round(natty_pct, 2),
                'cfp_pct':   round(cfp_pct,  2),
                'raw':       round(base_cfp + rec_cfp, 2),
            }
        except Exception:
            continue

    return result

def build_national_odds(year=None):
    """
    National championship + CFP Make % odds across the full 136-team field.

    Architecture:
      BASE (all 136): conf_standings_{year}.csv — W/L, MOV, DIFF, PF, PA, Streak
      SIGNAL:         cfp_rankings_history.csv  — live committee rankings
      SUPPLEMENT:     team_ratings.csv          — OVR/OFF/DEF for ~42 teams
      INJURIES:       injury_bulletin.csv        — live starter penalties

    Softmax over all 136 produces true national percentages.
    OVR is a quality supplement, not the anchor — record + rank drive the number.

    Returns dict: team_name → {'natty_pct': float, 'cfp_pct': float, 'raw': float}
    """
    if year is None:
        year = CURRENT_YEAR

    # ── 1. Base: conf_standings — all 136 teams ─────────────────────────────
    perf_map = load_team_performance(year=year)
    if not perf_map:
        return {}   # No conf_standings yet — can't compute

    # ── 2. CFP rank lookup ──────────────────────────────────────────────────
    cfp_rank_map = {}
    try:
        _rh = pd.read_csv('cfp_rankings_history.csv')
        _rh['YEAR'] = pd.to_numeric(_rh['YEAR'], errors='coerce')
        _rh['WEEK'] = pd.to_numeric(_rh['WEEK'], errors='coerce')
        _rh['RANK'] = pd.to_numeric(_rh['RANK'], errors='coerce')
        _cy = _rh[_rh['YEAR'] == int(year)]
        if not _cy.empty:
            _lw = _cy['WEEK'].max()
            _snap = _cy[_cy['WEEK'] == _lw]
            for _, _r in _snap.iterrows():
                _rk = int(_r['RANK']) if pd.notna(_r['RANK']) else 99
                if _rk > 0:
                    cfp_rank_map[str(_r['TEAM']).strip()] = _rk
    except Exception:
        pass

    # ── 3. OVR/OFF/DEF supplement for ~42 rated teams ─────────────────────
    ratings_map = load_team_ratings(year=year)  # team → {OVR, OFF, DEF}

    # ── 4. Live injury penalties ────────────────────────────────────────────
    inj_penalty_map = {}
    try:
        _inj = pd.read_csv('injury_bulletin.csv')
        _inj['Year']     = pd.to_numeric(_inj.get('Year'), errors='coerce')
        _inj['Week']     = pd.to_numeric(_inj.get('Week'), errors='coerce').fillna(0)
        _inj['WeeksOut'] = pd.to_numeric(_inj.get('WeeksOut'), errors='coerce').fillna(0)
        _inj['OVR']      = pd.to_numeric(_inj.get('OVR'), errors='coerce').fillna(75)
        _inj['_rem']     = (_inj['WeeksOut'] - (CURRENT_WEEK_NUMBER - _inj['Week'])).clip(lower=0)
        _inj = _inj[(_inj['Year'].fillna(-1).astype(int) == int(year)) &
                    (_inj['_rem'] > 0)].copy()
        for _, _ir in _inj.iterrows():
            _tm  = str(_ir.get('Team', '')).strip()
            _pos = str(_ir.get('Pos', _ir.get('Position', ''))).strip().upper()
            _ovr = float(_ir.get('OVR', 75))
            _wks = float(_ir.get('_rem', 0))
            if not _tm or _wks <= 0: continue
            _omult = max(0.1, min(1.0, (_ovr - 75) / 20.0))
            if _pos in ('QB',):
                _base = 32.0 if _wks >= 8 else (16.0 if _wks >= 3 else 7.0)
            elif _pos in ('WR','HB','TE'):
                _base = 12.0 if _wks >= 8 else (7.0 if _wks >= 3 else 2.5)
            elif _pos in ('LT','RT','LG','RG','C','MIKE','LEDG','REDG'):
                _base = 8.0 if _wks >= 8 else (4.0 if _wks >= 3 else 1.5)
            else:
                _base = 4.0 if _wks >= 8 else (2.0 if _wks >= 3 else 0.8)
            inj_penalty_map[_tm] = inj_penalty_map.get(_tm, 0.0) + _base * _omult
    except Exception:
        pass

    # ── 5. Fuzzy name helper ────────────────────────────────────────────────
    def _fuzzy_get(d, name):
        if name in d: return d[name]
        nl = name.lower()
        for k, v in d.items():
            if k.lower() == nl: return v
        nn = nl.replace('&', 'and')
        for k, v in d.items():
            if k.lower().replace('&', 'and') == nn: return v
        return None

    # ── 6. Score every team in conf_standings ───────────────────────────────
    rows = []
    for team, perf in perf_map.items():
        try:
            w    = int(perf.get('W', 0) or 0)
            l    = int(perf.get('L', 0) or 0)
            gp   = w + l
            if gp == 0:
                continue   # skip teams with no games (wouldn't be in standings)
            win_pct  = w / gp
            mov      = float(perf.get('MOV', 0.0) or 0.0)
            diff     = float(perf.get('DIFF', 0.0) or 0.0)
            pf_per_g = float(perf.get('PF', 0.0) or 0.0) / gp
            pa_per_g = float(perf.get('PA', 0.0) or 0.0) / gp
            stk      = int(perf.get('STK', 0) or 0)

            # CFP rank signal — primary committee verdict
            rank = _fuzzy_get(cfp_rank_map, team)
            rank_pts = cfp_rank_bonus(rank) * 1.4 if rank else 0.0

            # OVR supplement — compressed to avoid dominating
            # Scale OVR 65-99 → 0-25 pts (not 0-119 pts)
            _r = _fuzzy_get(ratings_map, team)
            if _r:
                ovr = float(_r.get('OVR') or _r.get('OVERALL') or 82)
                off = float(_r.get('OFF') or _r.get('OFFENSE') or 82)
                dfs = float(_r.get('DEF') or _r.get('DEFENSE') or 82)
                ovr_clamped = max(65.0, min(99.0, ovr))
                ovr_pts = ((ovr_clamped - 65.0) / 34.0) * 25.0   # 0–25 pts
                off_pts = ((max(65.0, min(99.0, off)) - 65.0) / 34.0) * 6.0
                def_pts = ((max(65.0, min(99.0, dfs)) - 65.0) / 34.0) * 6.0
            else:
                # No ratings — impute from MOV/PF
                # A dominant team with +20 MOV and 45 PF/G is probably high OVR
                _implied = 75.0 + min(10.0, mov * 0.5) + min(5.0, (pf_per_g - 28) * 0.15)
                ovr_clamped = max(65.0, min(90.0, _implied))
                ovr_pts = ((ovr_clamped - 65.0) / 34.0) * 20.0   # slightly less when imputed
                off_pts = 0.0
                def_pts = 0.0

            # ── Raw score — record + performance anchored, rank + quality as boosters ──
            raw = (
                # Record is the primary driver
                win_pct * 50.0                         # 0-50 pts — being undefeated matters
                + w * 2.0                              # games played depth (W-heavy)
                - l * 10.0                             # each loss punished directly
                - (l ** 1.7) * 4.0                    # accelerating multi-loss penalty

                # Margin of victory — quality of wins
                + min(mov, 35.0) * 0.9                 # capped at +35 to prevent runaway blowout teams
                + min(diff / max(gp, 1), 30.0) * 0.4  # point differential per game bonus

                # Scoring efficiency
                + max(0.0, pf_per_g - 25.0) * 0.5     # bonus above league baseline ~25 ppg
                - max(0.0, pa_per_g - 25.0) * 0.4     # defensive penalty

                # Win streak momentum
                + max(0, stk) * 1.5                    # active win streak bonus
                - max(0, -stk) * 2.0                   # active loss streak penalty

                # Committee signal
                + rank_pts                             # 0 if unranked, up to ~78 for #1

                # Quality supplement
                + ovr_pts + off_pts + def_pts          # 0–37 pts for top teams, 0 for unrated

                # Injury deduction
                - inj_penalty_map.get(team, 0.0)
            )

            # Hard elimination floors
            if l >= 4: raw -= 60
            elif l == 3: raw -= 30
            if rank is None and l >= 2: raw -= 20  # unranked + 2 losses = out of conversation
            if win_pct < 0.4: raw -= 30            # losing record programs eliminated

            rows.append({'team': team, 'raw': raw, 'rank': rank,
                         'w': w, 'l': l, 'mov': mov, 'ovr_pts': ovr_pts})
        except Exception:
            continue

    if not rows:
        return {}

    df_nat = pd.DataFrame(rows)

    # ── 7. Natty odds — softmax over full field ─────────────────────────────
    # Higher temperature than 6-team model — spread over 136 naturally compresses
    # individual percentages (correct: real natty probability for anyone is low)
    _nat_shift = df_nat['raw'] - df_nat['raw'].max()
    _nat_temp  = max(18.0, df_nat['raw'].std() * 1.1)
    _nat_exp   = np.exp(_nat_shift / _nat_temp)
    df_nat['natty_pct'] = (_nat_exp / _nat_exp.sum() * 100).round(2)

    # ── 8. CFP Make % — probability of being in top 12 ─────────────────────
    df_nat = df_nat.sort_values('raw', ascending=False).reset_index(drop=True)

    def _cfp_pct_calc(row):
        # Use actual CFP rank when known — committee has already voted
        actual_rank = row.get('rank')
        score_rank  = int(row.name) + 1
        # nan is truthy in Python but breaks int() — guard explicitly
        try:
            eff_rank = int(actual_rank) if (actual_rank is not None and actual_rank == actual_rank) else score_rank
        except (ValueError, TypeError):
            eff_rank = score_rank

        if eff_rank <= 4:   return round(min(97.0, 90 + (4 - eff_rank) * 2.0), 1)
        if eff_rank <= 8:   return round(min(88.0, 76 + (8 - eff_rank) * 3.0), 1)
        if eff_rank <= 12:  return round(min(74.0, 58 + (12 - eff_rank) * 4.0), 1)
        if eff_rank <= 16:  return round(min(52.0, 32 + (16 - eff_rank) * 5.0), 1)
        if eff_rank <= 25:  return round(min(28.0, 10 + (25 - eff_rank) * 2.0), 1)
        return round(max(1.0, 8.0 - (eff_rank - 25) * 0.3), 1)

    df_nat['cfp_pct'] = df_nat.apply(_cfp_pct_calc, axis=1)

    return {
        row['team']: {
            'natty_pct': row['natty_pct'],
            'cfp_pct':   row['cfp_pct'],
            'raw':       round(row['raw'], 1),
        }
        for _, row in df_nat.iterrows()
    }


def build_2041_model_table(r_2041, stats_df, rec_df):
    df = r_2041.copy()

    # TeamRatingsHistory.csv still uses the old column name — alias it to the new one.
    # The live roster computation will overwrite these values for the Speed Freaks tab,
    # but we need the column to exist under the new name throughout the model build.
    _old_gb = 'Game Breakers (90+ Speed & 90+ Acceleration)'
    _new_q90 = 'Quad 90 (90+ SPD, ACC, AGI & COD)'
    if _old_gb in df.columns and _new_q90 not in df.columns:
        df = df.rename(columns={_old_gb: _new_q90})

    # Zero-fill speed cols — no longer in TeamRatingsHistory.csv.
    # Live roster enrichment overwrites these after this function returns.
    # They must exist here so scoring formulas don't KeyError.
    for _spd_col in [
        'Team Speed (90+ Speed Guys)',
        'Quad 90 (90+ SPD, ACC, AGI & COD)',
        'Generational (96+ speed or 96+ Acceleration)',
        'Off Speed (90+ speed)',
        'Def Speed (90+ speed)',
        'Monsters',
        'Quick Hogs',
        'Cheat Codes',
        'Current CFP Ranking',
        'Current Record Wins',
        'Current Record Losses',
        'Combined Opponent Wins',
        'Combined Opponent Losses',
    ]:
        if _spd_col not in df.columns:
            df[_spd_col] = 0
        df[_spd_col] = pd.to_numeric(df[_spd_col], errors='coerce').fillna(0)

    # Pull conference from TeamRatingsHistory if present
    if 'CONFERENCE' not in df.columns:
        try:
            _rat_conf = pd.read_csv('TeamRatingsHistory.csv')[['TEAM','CONFERENCE']].drop_duplicates('TEAM')
            df = df.merge(_rat_conf, on='TEAM', how='left')
        except Exception:
            pass
    if 'CONFERENCE' not in df.columns:
        df['CONFERENCE'] = 'Other'
    df['CONFERENCE'] = df['CONFERENCE'].fillna('Other')

    stats_lookup = stats_df[['User', 'Career Win %', 'Career Record', 'Natties', 'Natty Apps', 'CFP Wins', 'CFP Losses', 'Conf Titles']].copy()
    stats_lookup = stats_lookup.rename(columns={'User': 'USER'})
    df = df.merge(stats_lookup, on='USER', how='left')

    df['Career Win %'] = pd.to_numeric(df['Career Win %'], errors='coerce').fillna(50.0)
    df['Recruit Score'] = df.apply(lambda x: get_recent_recruiting_score(rec_df, x['USER'], x['TEAM']), axis=1)
    df['QB Tier'] = df.apply(qb_label, axis=1)

    # --- schedule strength / resume inputs from latest TeamRatingsHistory ---
    for col in ['Combined Opponent Wins', 'Combined Opponent Losses', 'Current Record Wins', 'Current Record Losses']:
        if col not in df.columns:
            df[col] = 0
        df[col] = pd.to_numeric(df[col], errors='coerce').fillna(0)

    df['Opponent Games'] = df['Combined Opponent Wins'] + df['Combined Opponent Losses']
    df['Current Games'] = df['Current Record Wins'] + df['Current Record Losses']

    df['Opponent Win %'] = np.where(
        df['Opponent Games'] > 0,
        (df['Combined Opponent Wins'] / df['Opponent Games']) * 100,
        50.0
    )
    df['Current Win %'] = np.where(
        df['Current Games'] > 0,
        (df['Current Record Wins'] / df['Current Games']) * 100,
        50.0
    )

    max_opp_games = max(1.0, float(df['Opponent Games'].max()))
    opp_volume_pct = (df['Opponent Games'] / max_opp_games) * 100
    rank_map = dict(get_cfp_rankings_snapshot()[['Team', 'Rank']].values)
    ranked_counts = df['USER'].apply(lambda u: get_ranked_schedule_counts(scores, u, rank_map))
    df['Ranked Teams Faced'] = ranked_counts.apply(lambda x: x[0])
    df['Top 10 Teams Faced'] = ranked_counts.apply(lambda x: x[1])
    max_ranked = max(1.0, float(df['Ranked Teams Faced'].max()))
    max_top10 = max(1.0, float(df['Top 10 Teams Faced'].max()))
    ranked_pct = (df['Ranked Teams Faced'] / max_ranked) * 100
    top10_pct = (df['Top 10 Teams Faced'] / max_top10) * 100
    df['SOS'] = (
        df['Opponent Win %'] * 0.56
        + opp_volume_pct * 0.14
        + ranked_pct * 0.18
        + top10_pct * 0.12
    ).round(1)
    df['Resume Score'] = (df['Current Win %'] * 0.58 + df['SOS'] * 0.42).round(1)

    def qb_natty_bonus(row):
        if row['QB Tier'] == 'Elite':
            return 34.0
        if row['QB Tier'] == 'Leader':
            return 20.0
        if row['QB Tier'] == 'Average Joe':
            return -12.0
        if row['QB Tier'] == 'Ass':
            return -30.0
        return 0.0

    def qb_cfp_bonus(row):
        if row['QB Tier'] == 'Elite':
            return 24.0
        if row['QB Tier'] == 'Leader':
            return 15.0
        if row['QB Tier'] == 'Average Joe':
            return -9.0
        if row['QB Tier'] == 'Ass':
            return -22.0
        return 0.0

    def raw_contender_score(row):
        _u_s_rows = stats_df[stats_df['User'] == row['USER']]
        u_s = _u_s_rows.iloc[0] if not _u_s_rows.empty else pd.Series({
            'Natties': 0, 'Natty Apps': 0, 'CFP Wins': 0, 'Conf Titles': 0,
            'CFP Losses': 0, 'Career Win %': 0.5
        })

        # Pedigree: first 3 natties = coaching credibility (proven closer).
        # Beyond 3 it stops mattering — you still have to field a team this year.
        # Old formula gave 7-title coaches 168 pts before a single roster stat counted.
        # Hard cap prevents dynasty history from drowning out current team quality.
        natty_cred    = min(int(u_s.get('Natties', 0)), 3)
        pedigree_bonus = (
            natty_cred * 8
            + min(int(u_s.get('Natty Apps', 0)), 4) * 4
            + u_s['CFP Wins'] * 2.0
            + u_s['Conf Titles'] * 0.8
        )
        heartbreak_penalty = max(0, u_s['Natty Apps'] - u_s['Natties']) * 0.5
        cfp_fail_penalty = u_s['CFP Losses'] * 0.8

        team_speed_component = (
            row['Team Speed (90+ Speed Guys)'] * 3.0
            + row['Off Speed (90+ speed)'] * 1.55
            + row['Def Speed (90+ speed)'] * 1.55
        )
        cfp_bonus = cfp_rank_bonus(row.get('Current CFP Ranking', np.nan))

        raw = (
            row['OVERALL'] * 3.7
            + row['OFFENSE'] * 0.68
            + row['DEFENSE'] * 0.68
            + team_speed_component
            + row['Quad 90 (90+ SPD, ACC, AGI & COD)'] * 1.65
            + row['Generational (96+ speed or 96+ Acceleration)'] * 7.2
            + row['BCR_Val'] * 0.52
            + row['Recruit Score'] * 0.58
            + row['Career Win %'] * 0.26
            + row['Current Win %'] * 0.45
            + row['SOS'] * 0.40
            + row['Resume Score'] * 0.28
            + cfp_bonus * 1.15
            + qb_natty_bonus(row)
            + pedigree_bonus
            - heartbreak_penalty
            - cfp_fail_penalty
        )

        if row['OVERALL'] < 88:
            raw -= 24
        if row['OFFENSE'] < 85:
            raw -= 6
        if row['DEFENSE'] < 85:
            raw -= 6
        if row['BCR_Val'] < 35:
            raw -= 6
        if row['Team Speed (90+ Speed Guys)'] < 10:
            raw -= 6
        if row['Current Record Losses'] >= 1:
            _l = row['Current Record Losses']
            raw -= _l * 8.0 + (_l ** 1.6) * 3.5   # sharper: 1 loss ≈ -11, 2 ≈ -27, 3 ≈ -48

        # ── INJURY PENALTY — reads live from injury_bulletin.csv ────────────
        # Replaces old hardcoded INJURY_IMPACT dict which was stale bowl-week data.
        try:
            _inj_live_model = pd.read_csv('injury_bulletin.csv')
            _inj_live_model['Year']     = pd.to_numeric(_inj_live_model.get('Year'), errors='coerce')
            _inj_live_model['Week']     = pd.to_numeric(_inj_live_model.get('Week'), errors='coerce').fillna(0)
            _inj_live_model['WeeksOut'] = pd.to_numeric(_inj_live_model.get('WeeksOut'), errors='coerce').fillna(0)
            _inj_live_model['OVR']      = pd.to_numeric(_inj_live_model.get('OVR'), errors='coerce').fillna(75)
            _inj_live_model['_rem']     = (_inj_live_model['WeeksOut'] - (CURRENT_WEEK_NUMBER - _inj_live_model['Week'])).clip(lower=0)
            _inj_live_model = _inj_live_model[
                (_inj_live_model['Year'].fillna(-1).astype(int) == CURRENT_YEAR) &
                (_inj_live_model['_rem'] > 0) &
                (_inj_live_model['Team'].astype(str).str.strip() == str(row.get('TEAM','')).strip())
            ].copy()
            inj_penalty = 0.0
            for _, _ir in _inj_live_model.iterrows():
                _pos = str(_ir.get('Pos', _ir.get('Position', ''))).strip().upper()
                _ovr = float(_ir.get('OVR', 75) or 75)
                _wks = float(_ir.get('_rem', 0) or 0)
                if _wks <= 0: continue
                _omult = max(0.1, min(1.0, (_ovr - 75) / 20.0))
                if _pos in ('QB',):
                    _base = 32.0 if _wks >= 8 else (16.0 if _wks >= 3 else 7.0)
                elif _pos in ('WR','HB','TE'):
                    _base = 12.0 if _wks >= 8 else (7.0 if _wks >= 3 else 2.5)
                elif _pos in ('LT','RT','LG','RG','C','MIKE','LEDG','REDG'):
                    _base = 8.0 if _wks >= 8 else (4.0 if _wks >= 3 else 1.5)
                else:
                    _base = 4.0 if _wks >= 8 else (2.0 if _wks >= 3 else 0.8)
                inj_penalty += _base * _omult
            raw -= inj_penalty
        except Exception:
            pass
        return raw

    df['Contender Raw'] = df.apply(raw_contender_score, axis=1)

    temp = max(10.5, df['Contender Raw'].std() * 0.92)
    raw_shift = df['Contender Raw'] - df['Contender Raw'].max()
    exp_scores = np.exp(raw_shift / temp)
    natty_probs = (exp_scores / exp_scores.sum()) * 100
    df['Natty Odds'] = natty_probs.round(1)

    def stock_label(row):
        if row['Natty Odds'] >= 24 and row['Improvement'] >= 0:
            return "🚀 Surging"
        if row['Natty Odds'] >= 17:
            return "📈 Rising"
        if row['Improvement'] <= -2 or row['OVERALL'] < 82:
            return "📉 In Trouble"
        return "➖ Stable"

    df['Program Stock'] = df.apply(stock_label, axis=1)

    # ── PRESEASON VERSIONS (Dynasty News only) ────────────────────────────────
    # Uses only inputs known before the season starts — no win%, no CFP rank,
    # no resume, no current losses, no injuries.
    # Enriched with: full speed profile, BCR, recruiting history, roster
    # attrition net (departures vs incoming talent), QB tier, pedigree.
    # These are the 6 user teams scored against each other — not the national field.

    # ── Pre-load attrition signals for each user team ──────────────────────────
    # departure_year = CURRENT_YEAR - 1 (what they lost heading into this season)
    # incoming_year  = CURRENT_YEAR     (what arrived)
    _atr_penalty = {}   # team → raw penalty pts from departures
    _atr_bonus   = {}   # team → raw bonus pts from incoming talent
    try:
        _dep_year = CURRENT_YEAR - 1
        _inc_year = CURRENT_YEAR

        # NFL departures — starters lost to the draft
        _nfl_dep = pd.read_csv('attrition_nfl.csv')
        _nfl_dep['Year'] = pd.to_numeric(_nfl_dep.get('Year'), errors='coerce')
        _nfl_dep['OVR']  = pd.to_numeric(_nfl_dep.get('OVR'), errors='coerce').fillna(80)
        _nfl_dep = _nfl_dep[_nfl_dep['Year'].fillna(-1).astype(int) == _dep_year].copy()
        for _, _dr in _nfl_dep.iterrows():
            _tm = str(_dr.get('Team', '')).strip()
            _ovr = float(_dr.get('OVR', 80))
            _ws  = str(_dr.get('Was Starter', '')).strip().lower() in ('yes','true','1')
            pts = ((_ovr - 75) / 20.0) * (8.0 if _ws else 3.0)
            _atr_penalty[_tm] = _atr_penalty.get(_tm, 0.0) + pts
    except Exception:
        pass

    try:
        # Transfer portal exits
        _xfer_out = pd.read_csv('attrition_transfers.csv')
        _xfer_out['Year'] = pd.to_numeric(_xfer_out.get('Year'), errors='coerce')
        _xfer_out['OVR']  = pd.to_numeric(_xfer_out.get('OVR'), errors='coerce').fillna(78)
        _xfer_out = _xfer_out[_xfer_out['Year'].fillna(-1).astype(int) == _dep_year].copy()
        for _, _xr in _xfer_out.iterrows():
            _tm = str(_xr.get('Team', '')).strip()
            _ovr = float(_xr.get('OVR', 78))
            _st  = str(_xr.get('TransferStatus', '')).strip().lower()
            if _st != 'leaving': continue
            pts = ((_ovr - 75) / 20.0) * 5.0
            _atr_penalty[_tm] = _atr_penalty.get(_tm, 0.0) + pts
    except Exception:
        pass

    try:
        # Incoming recruits / transfers
        _inc = pd.read_csv('attrition_incoming.csv')
        _inc['Year']  = pd.to_numeric(_inc.get('Year'), errors='coerce')
        _inc['Stars'] = pd.to_numeric(_inc.get('Stars', _inc.get('StarRating', 0)), errors='coerce').fillna(0)
        _inc = _inc[_inc['Year'].fillna(-1).astype(int) == _inc_year].copy()
        for _, _ir in _inc.iterrows():
            _tm   = str(_ir.get('Team', '')).strip()
            stars = float(_ir.get('Stars', 0))
            role  = str(_ir.get('ProjectedRole', '')).strip().lower()
            role_mult = 1.5 if role == 'starter' else (1.0 if role == 'rotation' else 0.4)
            pts = (stars / 5.0) * role_mult * 4.0
            _atr_bonus[_tm] = _atr_bonus.get(_tm, 0.0) + pts
    except Exception:
        pass

    def preseason_contender_score(row):
        _u_s_rows = stats_df[stats_df['User'] == row['USER']]
        u_s = _u_s_rows.iloc[0] if not _u_s_rows.empty else pd.Series({
            'Natties': 0, 'Natty Apps': 0, 'CFP Wins': 0, 'Conf Titles': 0,
            'CFP Losses': 0, 'Career Win %': 0.5
        })
        natty_cred = min(int(u_s.get('Natties', 0)), 3)
        pedigree_bonus = (
            natty_cred * 8
            + min(int(u_s.get('Natty Apps', 0)), 4) * 4
            + u_s['CFP Wins'] * 2.0
            + u_s['Conf Titles'] * 0.8
        )
        heartbreak_penalty = max(0, u_s['Natty Apps'] - u_s['Natties']) * 0.5
        cfp_fail_penalty = u_s['CFP Losses'] * 0.8

        team_speed_component = (
            row['Team Speed (90+ Speed Guys)'] * 3.0
            + row['Off Speed (90+ speed)'] * 1.55
            + row['Def Speed (90+ speed)'] * 1.55
        )

        # Attrition net — talent balance heading into the season
        _tm = str(row.get('TEAM', '')).strip()
        _dep_pts = _atr_penalty.get(_tm, 0.0)
        _inc_pts = _atr_bonus.get(_tm, 0.0)
        _net_atr = _inc_pts - _dep_pts   # positive = net gain, negative = net loss

        # Roster trajectory — OVR improvement year-over-year
        improvement = float(row.get('Improvement', 0) or 0)

        raw = (
            row['OVERALL'] * 3.7
            + row['OFFENSE'] * 0.68
            + row['DEFENSE'] * 0.68
            + team_speed_component
            + row['Quad 90 (90+ SPD, ACC, AGI & COD)'] * 1.65
            + row['Generational (96+ speed or 96+ Acceleration)'] * 7.2
            + row['BCR_Val'] * 0.52
            + row['Recruit Score'] * 0.58
            + row['Career Win %'] * 0.26
            + row['SOS'] * 0.40
            + improvement * 2.5              # trajectory signal — rising program bonus
            + _net_atr * 0.8                 # attrition net: gaining > losing adds pts
            + qb_natty_bonus(row)
            + pedigree_bonus
            - heartbreak_penalty
            - cfp_fail_penalty
            + conf_bonus(row.get('CONFERENCE', 'Other'))
        )

        if row['OVERALL'] < 88:   raw -= 24
        if row['OFFENSE'] < 85:   raw -= 6
        if row['DEFENSE'] < 85:   raw -= 6
        if row['BCR_Val'] < 35:   raw -= 6
        if row['Team Speed (90+ Speed Guys)'] < 10: raw -= 6

        return raw

    _pre_raw = df.apply(preseason_contender_score, axis=1)
    _pre_temp = max(10.5, _pre_raw.std() * 0.92)
    _pre_shift = _pre_raw - _pre_raw.max()
    _pre_exp = np.exp(_pre_shift / _pre_temp)
    df['Preseason Natty Odds'] = (_pre_exp / _pre_exp.sum() * 100).round(1)

    def preseason_power_index(row):
        _u_s_pi_rows = stats_df[stats_df['User'] == row['USER']]
        u_s_pi = _u_s_pi_rows.iloc[0] if not _u_s_pi_rows.empty else pd.Series({'Natties': 0})
        coaching_cred = min(int(u_s_pi.get('Natties', 0)), 2) * 2.5
        return round(
            row['OVERALL'] * 2.25
            + row['OFFENSE'] * 0.82
            + row['DEFENSE'] * 0.82
            + row['Team Speed (90+ Speed Guys)'] * 2.1
            + row['Quad 90 (90+ SPD, ACC, AGI & COD)'] * 1.6
            + row['Generational (96+ speed or 96+ Acceleration)'] * 5.2
            + row['BCR_Val'] * 0.56
            + row['Recruit Score'] * 0.50
            + row['Improvement'] * 4.0
            + row['Career Win %'] * 0.60
            + row['SOS'] * 0.38
            + qb_cfp_bonus(row) * 0.95
            + row['CFP Wins'] * 1.2
            - row['CFP Losses'] * 1.2
            + coaching_cred
            + conf_bonus(row.get('CONFERENCE', 'Other')),
            1
        )

    df['Preseason PI'] = df.apply(preseason_power_index, axis=1)

    _pre_cfp_raw = (
        df['Preseason PI'] * 0.66
        + df['OVERALL'] * 1.35
        + df['Team Speed (90+ Speed Guys)'] * 1.95
        + df['Off Speed (90+ speed)'] * 0.75
        + df['Def Speed (90+ speed)'] * 0.75
        + df['Quad 90 (90+ SPD, ACC, AGI & COD)'] * 1.25
        + df['Generational (96+ speed or 96+ Acceleration)'] * 3.1
        + df['Recruit Score'] * 0.46
        + df['Career Win %'] * 0.18
        + df['SOS'] * 0.58
        + df.apply(qb_cfp_bonus, axis=1)
        + df['CONFERENCE'].apply(conf_bonus)
    )
    _pre_cfp_min = _pre_cfp_raw.min()
    _pre_cfp_spread = max(1, _pre_cfp_raw.max() - _pre_cfp_min)
    df['Preseason CFP %'] = (16 + ((_pre_cfp_raw - _pre_cfp_min) / _pre_cfp_spread * 66)).round(1)
    df['Preseason CFP %'] = df['Preseason CFP %'].clip(lower=12, upper=82)

    def power_index(row):
        # Coaching credibility: first 2 natties prove you can execute.
        # Beyond that your roster matters more than your trophy case. Hard cap at 2.
        _u_s_pi_rows = stats_df[stats_df['User'] == row['USER']]
        u_s_pi = _u_s_pi_rows.iloc[0] if not _u_s_pi_rows.empty else pd.Series({'Natties': 0})
        coaching_cred = min(int(u_s_pi.get('Natties', 0)), 2) * 2.5
        return round(
            row['OVERALL'] * 2.25
            + row['OFFENSE'] * 0.82
            + row['DEFENSE'] * 0.82
            + row['Team Speed (90+ Speed Guys)'] * 2.1
            + row['Quad 90 (90+ SPD, ACC, AGI & COD)'] * 1.6
            + row['Generational (96+ speed or 96+ Acceleration)'] * 5.2
            + row['BCR_Val'] * 0.56
            + row['Recruit Score'] * 0.50
            + row['Improvement'] * 4.0
            + row['Career Win %'] * 0.60
            + row['Current Win %'] * 0.50
            + row['SOS'] * 0.38
            + cfp_rank_bonus(row.get('Current CFP Ranking', np.nan)) * 0.86
            + qb_cfp_bonus(row) * 0.95
            + row['CFP Wins'] * 1.2
            - row['CFP Losses'] * 1.2
            + coaching_cred,
            1
        )

    df['Power Index'] = df.apply(power_index, axis=1)
    df['Team Speed Score'] = (
        df['Team Speed (90+ Speed Guys)'] * 2.2
        + df['Off Speed (90+ speed)'] * 1.0
        + df['Def Speed (90+ speed)'] * 1.0
        + df['Quad 90 (90+ SPD, ACC, AGI & COD)'] * 2.5
    ) * (1 + df['Generational (96+ speed or 96+ Acceleration)'] * 0.16
           + df['Quad 90 (90+ SPD, ACC, AGI & COD)'] * 0.07)
    df['Team Speed Score'] = df['Team Speed Score'].round(1)
    df['Speedometer'] = df['Team Speed Score'].apply(team_speed_to_mph)

    def where_is_the_speed(row):
        off_fast = row['Off Speed (90+ speed)'] > 5
        def_fast = row['Def Speed (90+ speed)'] > 5
        mph = pd.to_numeric(row.get('Speedometer', np.nan), errors='coerce')
        if (not off_fast) and (not def_fast) and (not pd.isna(mph)) and mph < 65:
            return 'Non-Existent'
        if off_fast and def_fast:
            return 'Off & Def'
        if off_fast:
            return 'Offense'
        if def_fast:
            return 'Defense'
        return 'Balanced'

    df['Where is the Speed?'] = df.apply(where_is_the_speed, axis=1)

    cfp_raw = (
        df['Power Index'] * 0.66
        + df['OVERALL'] * 1.35
        + df['Team Speed (90+ Speed Guys)'] * 1.95
        + df['Off Speed (90+ speed)'] * 0.75
        + df['Def Speed (90+ speed)'] * 0.75
        + df['Quad 90 (90+ SPD, ACC, AGI & COD)'] * 1.25
        + df['Generational (96+ speed or 96+ Acceleration)'] * 3.1
        + df['Recruit Score'] * 0.46
        + df['Career Win %'] * 0.18
        + df['Current Win %'] * 0.70
        + df['SOS'] * 0.58
        + df['Resume Score'] * 0.42
        + df['Current CFP Ranking'].apply(cfp_rank_bonus) * 1.95
        + df.apply(qb_cfp_bonus, axis=1)
        # Natties/NattyApps removed — consistent with Power Index & Natty Odds fix
    )
    cfp_min = cfp_raw.min()
    cfp_spread = max(1, cfp_raw.max() - cfp_min)
    df['CFP Odds'] = (16 + ((cfp_raw - cfp_min) / cfp_spread * 66)).round(0).astype(int)
    df['CFP Odds'] = df['CFP Odds'].clip(lower=12, upper=82)

    power_min = df['Power Index'].min()
    power_max = df['Power Index'].max()
    power_spread = max(1, power_max - power_min)
    df['Projected Wins'] = (6.2 + ((df['Power Index'] - power_min) / power_spread * 5.3)).round(1)
    df['Projected Wins'] = df['Projected Wins'].clip(lower=5.5, upper=11.5)

    df['Collapse Risk'] = (
        66
        - (df['OVERALL'] - 80) * 2.0
        - df['Improvement'] * 4.5
        - df['BCR_Val'] * 0.35
        - df['Recruit Score'] * 0.12
        - df['Generational (96+ speed or 96+ Acceleration)'] * 3.0
        - df['SOS'] * 0.18
        - df['Current Win %'] * 0.10
        - df['Current CFP Ranking'].apply(cfp_rank_bonus) * 0.25
        - df.apply(qb_cfp_bonus, axis=1) * 0.4
    ).round(0).astype(int)
    df['Collapse Risk'] = df['Collapse Risk'].clip(lower=8, upper=72)

    return df.sort_values(['Power Index', 'Natty Odds'], ascending=False).reset_index(drop=True)


def project_loss_scenarios(row):
    natty = float(pd.to_numeric(row.get('Natty Odds', 0), errors='coerce'))
    cfp = float(pd.to_numeric(row.get('CFP Odds', 0), errors='coerce'))
    overall = float(pd.to_numeric(row.get('OVERALL', 0), errors='coerce'))
    team_speed = float(pd.to_numeric(row.get('Team Speed (90+ Speed Guys)', 0), errors='coerce'))
    qb_tier = str(row.get('QB Tier', '')).strip()
    cfp_rank = row.get('Current CFP Ranking', np.nan)
    ranked_now = pd.notna(cfp_rank)

    base_unranked_natty_drop = 7.5
    base_ranked_natty_drop = 4.0
    base_unranked_cfp_drop = 16.0
    base_ranked_cfp_drop = 8.0

    if overall >= 90:
        base_unranked_natty_drop += 2.0
        base_unranked_cfp_drop += 2.5
    elif overall <= 84:
        base_ranked_natty_drop += 1.0
        base_ranked_cfp_drop += 2.0

    if team_speed >= 12:
        base_unranked_natty_drop += 1.5
        base_unranked_cfp_drop += 1.5

    if qb_tier == 'Elite':
        base_unranked_natty_drop += 1.8
        base_ranked_natty_drop += 0.8
        base_unranked_cfp_drop += 1.8
        base_ranked_cfp_drop += 0.8
    elif qb_tier == 'Leader':
        base_unranked_natty_drop += 1.0
        base_ranked_natty_drop += 0.4
        base_unranked_cfp_drop += 1.0
        base_ranked_cfp_drop += 0.4
    elif qb_tier == 'Ass':
        base_unranked_natty_drop -= 1.0
        base_ranked_natty_drop -= 0.5
        base_unranked_cfp_drop -= 1.5
        base_ranked_cfp_drop -= 1.0

    if ranked_now:
        base_unranked_natty_drop += 1.8
        base_unranked_cfp_drop += 3.0

    natty_unranked = max(0.1, round(natty - base_unranked_natty_drop, 1))
    natty_ranked = max(0.1, round(natty - base_ranked_natty_drop, 1))
    cfp_unranked = max(1, int(round(cfp - base_unranked_cfp_drop, 0)))
    cfp_ranked = max(1, int(round(cfp - base_ranked_cfp_drop, 0)))

    return pd.Series({
        'Natty if Lose to Unranked': natty_unranked,
        'Natty if Lose to Ranked': natty_ranked,
        'CFP if Lose to Unranked': cfp_unranked,
        'CFP if Lose to Ranked': cfp_ranked
    })


def get_team_schedule_summary(scores_df, user):
    user = str(user).strip().title()
    games = scores_df[(scores_df['V_User_Final'] == user) | (scores_df['H_User_Final'] == user)].copy()

    if games.empty:
        return 0, 0, 0.0, 0.0

    wins = len(games[
        ((games['V_User_Final'] == user) & (games['V_Pts'] > games['H_Pts'])) |
        ((games['H_User_Final'] == user) & (games['H_Pts'] > games['V_Pts']))
    ])
    losses = len(games) - wins

    points_for = np.where(games['V_User_Final'] == user, games['V_Pts'], games['H_Pts']).sum()
    points_against = np.where(games['V_User_Final'] == user, games['H_Pts'], games['V_Pts']).sum()
    avg_margin = round((points_for - points_against) / max(1, len(games)), 1)

    return wins, losses, round(points_for / max(1, len(games)), 1), avg_margin


def load_scores_master(year=None, multi_year=False, **kwargs):
    """
    Load game schedule/results data. Source of truth by year:
    - 2042+: schedule_{YEAR}.csv  (full league, all games)
    - Pre-2042: CPUscores_MASTER.csv  (legacy, user games only)
    - multi_year=True: combines all available sources across all seasons
    """
    import glob as _glob
    import re as _re

    def _clean_team_cols(df):
        """Strip watcher artifacts like '2 Panama City' → 'Panama City' from team name columns."""
        for _col in ('Visitor', 'Home', 'VISITOR', 'HOME'):
            if _col in df.columns:
                df[_col] = df[_col].astype(str).apply(
                    lambda t: _re.sub(r'^\d+\s+', '', t.strip())
                )
        return df

    def _read(path, **kw):
        try:
            df = pd.read_csv(path, **kw)
            return _clean_team_cols(df)
        except Exception:
            return pd.DataFrame()

    if multi_year:
        parts = []
        # CPUscores loaded FIRST — schedule_{YEAR}.csv last so keep='last' always
        # preserves schedule data (with user tags) over stale CPUscores entries.
        if os.path.exists('CPUscores_MASTER.csv'):
            parts.append(_read('CPUscores_MASTER.csv', **kwargs))
        for yf in sorted(_glob.glob('CPUscores_MASTER_*.csv')):
            parts.append(_read(yf, **kwargs))
        # schedule files LAST = wins on any duplicate row
        for yf in sorted(_glob.glob('schedule_*.csv')):
            parts.append(_read(yf, **kwargs))
        if not parts:
            return pd.DataFrame()
        combined = pd.concat(parts, ignore_index=True)
        for c in ['YEAR', 'Week']:
            if c in combined.columns:
                combined[c] = pd.to_numeric(combined[c], errors='coerce')
        dk = [c for c in ['YEAR', 'Week', 'Visitor', 'Home'] if c in combined.columns]
        if dk:
            combined = combined.drop_duplicates(subset=dk, keep='last')
        return combined

    target_year = int(year) if year else CURRENT_YEAR
    # 2042+: prefer schedule_{YEAR}.csv
    schedule_file = f'schedule_{target_year}.csv'
    if os.path.exists(schedule_file):
        return _read(schedule_file, **kwargs)
    # Fallback: CPUscores_MASTER_{YEAR}.csv
    year_master = f'CPUscores_MASTER_{target_year}.csv'
    if os.path.exists(year_master):
        return _read(year_master, **kwargs)
    # Final fallback: legacy master (filter by year)
    if os.path.exists('CPUscores_MASTER.csv'):
        df = _read('CPUscores_MASTER.csv', **kwargs)
        if not df.empty and 'YEAR' in df.columns:
            df['YEAR'] = pd.to_numeric(df['YEAR'], errors='coerce')
            return df[df['YEAR'].fillna(-1).astype(int) == target_year]
        return df
    return pd.DataFrame()


def get_full_league_schedule(year=None):
    """Load full league schedule from schedule_{YEAR}.csv, fallback to CPUscores_MASTER."""
    target_year = int(year) if year else CURRENT_YEAR
    year_file = f"schedule_{target_year}.csv"
    try:
        if os.path.exists(year_file):
            df = pd.read_csv(year_file)
        elif os.path.exists("CPUscores_MASTER.csv"):
            df = load_scores_master(CURRENT_YEAR)
            df['YEAR'] = pd.to_numeric(df.get('YEAR'), errors='coerce')
            df = df[df['YEAR'].fillna(-1).astype(int) == target_year]
        else:
            return pd.DataFrame()
        df['YEAR']       = pd.to_numeric(df.get('YEAR'),       errors='coerce')
        df['Week']       = pd.to_numeric(df.get('Week'),       errors='coerce')
        df['Vis Score']  = pd.to_numeric(df.get('Vis Score'),  errors='coerce')
        df['Home Score'] = pd.to_numeric(df.get('Home Score'), errors='coerce')
        return df
    except Exception:
        return pd.DataFrame()


def get_team_current_streak(scores_df, team, current_week):
    """Return (streak_count, 'W'|'L') for a team's current win/loss streak."""
    completed = scores_df[
        (scores_df['Status'].astype(str).str.upper() == 'FINAL') &
        (scores_df['Week'] <= current_week) &
        ((scores_df['Visitor'].astype(str).str.strip() == team) |
         (scores_df['Home'].astype(str).str.strip() == team))
    ].sort_values('Week', ascending=False)

    if completed.empty:
        return 0, ''

    results = []
    for _, g in completed.iterrows():
        vis = str(g.get('Visitor','')).strip()
        vs  = safe_num(g.get('Vis Score'), 0)
        hs  = safe_num(g.get('Home Score'), 0)
        if vis == team:
            results.append('W' if vs > hs else 'L')
        else:
            results.append('W' if hs > vs else 'L')

    if not results:
        return 0, ''
    streak_type = results[0]
    count = 0
    for r in results:
        if r == streak_type:
            count += 1
        else:
            break
    return count, streak_type


def get_team_record(scores_df, team, through_week=None):
    """Return (wins, losses) for any team through a given week."""
    completed = scores_df[scores_df['Status'].astype(str).str.upper() == 'FINAL'].copy()
    if through_week:
        completed = completed[completed['Week'] <= through_week]
    team_games = completed[
        (completed['Visitor'].astype(str).str.strip() == team) |
        (completed['Home'].astype(str).str.strip() == team)
    ]
    wins = losses = 0
    for _, g in team_games.iterrows():
        vis = str(g.get('Visitor','')).strip()
        vs  = safe_num(g.get('Vis Score'), 0)
        hs  = safe_num(g.get('Home Score'), 0)
        if vis == team:
            if vs > hs: wins += 1
            else: losses += 1
        else:
            if hs > vs: wins += 1
            else: losses += 1
    return wins, losses


def get_opponent_context(scores_df, user_team, user_week, current_week):
    """Return a context string about a user's upcoming opponent."""
    try:
        upcoming = scores_df[
            (scores_df['Status'].astype(str).str.upper() != 'FINAL') &
            (scores_df['Week'] == int(user_week)) &
            ((scores_df['Visitor'].astype(str).str.strip() == user_team) |
             (scores_df['Home'].astype(str).str.strip() == user_team))
        ]
        if upcoming.empty:
            return ''

        row = upcoming.iloc[0]
        vis = str(row.get('Visitor','')).strip()
        opp = str(row.get('Home','')).strip() if vis == user_team else vis

        streak_n, streak_t = get_team_current_streak(scores_df, opp, current_week)
        w, l = get_team_record(scores_df, opp, current_week)
        opp_rank = row.get('Visitor Rank') if vis != user_team else row.get('Home Rank')
        rank_str = f"#{int(opp_rank)} " if pd.notna(opp_rank) and str(opp_rank) not in ('','nan') else ''

        if streak_n >= 3:
            hot_cold = f"on a {streak_n}-game {streak_t} streak"
        elif streak_n == 2:
            hot_cold = f"winners of 2 straight" if streak_t == 'W' else f"losers of 2 straight"
        else:
            hot_cold = ""

        record_str = f"{w}-{l}" if (w + l) > 0 else ""
        parts = [p for p in [rank_str + opp, record_str, hot_cold] if p]
        return " · ".join(parts)
    except Exception:
        return ''


def get_league_upsets(scores_df, week, rank_threshold=15):
    """Return list of upset results — unranked beating ranked teams — for a given week."""
    week_games = scores_df[
        (scores_df['Status'].astype(str).str.upper() == 'FINAL') &
        (scores_df['Week'].fillna(-1).astype(int) == int(week))
    ].copy()

    upsets = []
    for _, g in week_games.iterrows():
        vs  = safe_num(g.get('Vis Score'), 0)
        hs  = safe_num(g.get('Home Score'), 0)
        v_rank = g.get('Visitor Rank')
        h_rank = g.get('Home Rank')
        vis = str(g.get('Visitor','')).strip()
        hom = str(g.get('Home','')).strip()

        v_ranked = pd.notna(v_rank) and str(v_rank) not in ('','nan') and int(float(v_rank)) <= rank_threshold
        h_ranked = pd.notna(h_rank) and str(h_rank) not in ('','nan') and int(float(h_rank)) <= rank_threshold

        if v_ranked and not h_ranked and hs > vs:
            upsets.append({'ranked': vis, 'rank': int(float(v_rank)), 'winner': hom, 'score': f"{int(hs)}-{int(vs)}"})
        elif h_ranked and not v_ranked and vs > hs:
            upsets.append({'ranked': hom, 'rank': int(float(h_rank)), 'winner': vis, 'score': f"{int(vs)}-{int(hs)}"})

    return sorted(upsets, key=lambda x: x['rank'])


def get_hot_cpu_programs(scores_df, current_week, win_streak_min=4):
    """Return CPU teams on big winning streaks — potential Cinderella/storyline material."""
    all_teams = set(scores_df['Visitor'].dropna().astype(str).str.strip().tolist() +
                    scores_df['Home'].dropna().astype(str).str.strip().tolist())
    hot = []
    for team in all_teams:
        n, t = get_team_current_streak(scores_df, team, current_week)
        if t == 'W' and n >= win_streak_min:
            w, l = get_team_record(scores_df, team, current_week)
            # Check if unranked (no rank in recent game)
            recent = scores_df[
                ((scores_df['Visitor'].astype(str).str.strip() == team) |
                 (scores_df['Home'].astype(str).str.strip() == team)) &
                (scores_df['Week'] == current_week)
            ]
            is_ranked = False
            if not recent.empty:
                row = recent.iloc[0]
                rk = row.get('Visitor Rank') if str(row.get('Visitor','')).strip() == team else row.get('Home Rank')
                is_ranked = pd.notna(rk) and str(rk) not in ('','nan')
            hot.append({'team': team, 'streak': n, 'record': f"{w}-{l}", 'ranked': is_ranked})
    return sorted(hot, key=lambda x: (-x['streak'], x['team']))


def get_quality_win_context(scores_df, user_team, through_week):
    """Return count of wins over ranked opponents for a user's team."""
    completed = scores_df[
        (scores_df['Status'].astype(str).str.upper() == 'FINAL') &
        (scores_df['Week'] <= through_week)
    ]
    wins_vs_ranked = 0
    best_rank_beaten = None
    for _, g in completed.iterrows():
        vis = str(g.get('Visitor','')).strip()
        vs  = safe_num(g.get('Vis Score'), 0)
        hs  = safe_num(g.get('Home Score'), 0)
        v_rank = g.get('Visitor Rank')
        h_rank = g.get('Home Rank')

        if vis == user_team and vs > hs:
            opp_rank = h_rank
        elif str(g.get('Home','')).strip() == user_team and hs > vs:
            opp_rank = v_rank
        else:
            continue

        if pd.notna(opp_rank) and str(opp_rank) not in ('','nan'):
            rk = int(float(opp_rank))
            wins_vs_ranked += 1
            if best_rank_beaten is None or rk < best_rank_beaten:
                best_rank_beaten = rk

    return wins_vs_ranked, best_rank_beaten


# ══════════════════════════════════════════════════════════════════════════════
# TRUE SOS / SOR / FPI ANALYTICS ENGINE
# ══════════════════════════════════════════════════════════════════════════════

def compute_power_ratings(scores_df, year=None, week_cap=None, iterations=50):
    """
    Iterative Colley-matrix-inspired power ratings (FPI).

    FPI for team i = avg(margin_of_victory_adjusted) vs opponent FPI.
    Iterates until stable. Returns dict: {team: fpi_score}

    MOV is capped at 28 to prevent blowouts dominating.
    Home-field adjustment: -3 from home team's margin.
    """
    df = scores_df.copy()
    if year:
        df = df[df['YEAR'].fillna(-1).astype(int) == int(year)]
    if week_cap:
        df = df[df['Week'].fillna(0).astype(int) <= int(week_cap)]
    df = df[df['Status'].astype(str).str.upper() == 'FINAL'].copy()
    df['Vis Score']  = pd.to_numeric(df['Vis Score'],  errors='coerce')
    df['Home Score'] = pd.to_numeric(df['Home Score'], errors='coerce')
    df = df.dropna(subset=['Vis Score', 'Home Score'])
    if df.empty:
        return {}

    all_teams = set(df['Visitor'].dropna().astype(str).str.strip().tolist() +
                    df['Home'].dropna().astype(str).str.strip().tolist())

    # Strip watcher misread artifacts like "2 Panama City" → "Panama City"
    # GPT sometimes prepends a row number to the team name
    import re as _re
    def _clean_team(t):
        return _re.sub(r'^\d+\s+', '', str(t).strip())
    df['Visitor'] = df['Visitor'].astype(str).apply(_clean_team)
    df['Home']    = df['Home'].astype(str).apply(_clean_team)
    all_teams = set(df['Visitor'].tolist() + df['Home'].tolist())
    fpi = {t: 0.0 for t in all_teams}

    for _ in range(iterations):
        new_fpi = {}
        for team in all_teams:
            t_games = df[(df['Visitor'].astype(str).str.strip() == team) |
                         (df['Home'].astype(str).str.strip() == team)]
            if t_games.empty:
                new_fpi[team] = 0.0
                continue
            values = []
            for _, g in t_games.iterrows():
                vis = str(g['Visitor']).strip()
                vs  = float(g['Vis Score'])
                hs  = float(g['Home Score'])
                is_home = vis != team
                # Raw MOV from team's perspective, home adjustment
                raw_mov = (hs - vs) if is_home else (vs - hs)
                ha_adj  = 3.0 if is_home else -3.0  # home field ~3 pts
                adj_mov = raw_mov - ha_adj
                adj_mov = max(-28, min(28, adj_mov))  # cap at 28
                opp = str(g['Home']).strip() if vis == team else vis
                opp_fpi = fpi.get(opp, 0.0)
                # FPI component: adjusted MOV + opponent quality adjustment
                values.append(adj_mov + opp_fpi * 0.5)
            new_fpi[team] = round(sum(values) / len(values), 3) if values else 0.0
        # Normalize to mean=0
        vals = list(new_fpi.values())
        mean = sum(vals) / len(vals) if vals else 0
        new_fpi = {t: round(v - mean, 3) for t, v in new_fpi.items()}
        if all(abs(new_fpi.get(t, 0) - fpi.get(t, 0)) < 0.001 for t in all_teams):
            break
        fpi = new_fpi

    return fpi


def compute_sos(scores_df, team, year=None, week_cap=None, fpi_ratings=None):
    """
    Strength of Schedule: average FPI of all opponents faced.
    If fpi_ratings not provided, uses opponent win percentage instead.
    Returns (sos_score, opponents_list)
    """
    df = scores_df.copy()
    if year:
        df = df[df['YEAR'].fillna(-1).astype(int) == int(year)]
    if week_cap:
        df = df[df['Week'].fillna(0).astype(int) <= int(week_cap)]

    team_games = df[(df['Visitor'].astype(str).str.strip() == team) |
                    (df['Home'].astype(str).str.strip() == team)]
    if team_games.empty:
        return 0.0, []

    opponents = []
    for _, g in team_games.iterrows():
        vis = str(g['Visitor']).strip()
        opp = str(g['Home']).strip() if vis == team else vis
        opponents.append(opp)

    if fpi_ratings:
        opp_scores = [fpi_ratings.get(o, 0.0) for o in opponents]
        sos = round(sum(opp_scores) / len(opp_scores), 3) if opp_scores else 0.0
    else:
        # Fallback: win percentage of opponents
        completed = df[df['Status'].astype(str).str.upper() == 'FINAL'].copy()
        completed['Vis Score']  = pd.to_numeric(completed['Vis Score'],  errors='coerce')
        completed['Home Score'] = pd.to_numeric(completed['Home Score'], errors='coerce')
        opp_wpcts = []
        for opp in opponents:
            w, l = get_team_record(completed, opp, week_cap)
            wpct = w / max(1, w + l)
            opp_wpcts.append(wpct)
        sos = round(sum(opp_wpcts) / len(opp_wpcts), 3) if opp_wpcts else 0.0

    return sos, opponents


def compute_sor(scores_df, team, year=None, week_cap=None, fpi_ratings=None):
    """
    Strength of Record: credit wins over good opponents, penalize losses to weak ones.
    Each win = +opponent_fpi_percentile, each loss = -inverse_fpi_percentile.
    Returns sor_score (higher = better résumé).
    """
    df = scores_df.copy()
    if year:
        df = df[df['YEAR'].fillna(-1).astype(int) == int(year)]
    if week_cap:
        df = df[df['Week'].fillna(0).astype(int) <= int(week_cap)]
    completed = df[df['Status'].astype(str).str.upper() == 'FINAL'].copy()
    completed['Vis Score']  = pd.to_numeric(completed['Vis Score'],  errors='coerce')
    completed['Home Score'] = pd.to_numeric(completed['Home Score'], errors='coerce')
    completed = completed.dropna(subset=['Vis Score', 'Home Score'])

    team_games = completed[(completed['Visitor'].astype(str).str.strip() == team) |
                           (completed['Home'].astype(str).str.strip() == team)]
    if team_games.empty:
        return 0.0

    if not fpi_ratings:
        return 0.0

    # Build percentile ranks of FPI
    all_fpis = sorted(fpi_ratings.values())
    n = len(all_fpis)

    def _pct(fpi_val):
        if n == 0: return 0.5
        pos = sum(1 for v in all_fpis if v <= fpi_val)
        return pos / n

    score_parts = []
    for _, g in team_games.iterrows():
        vis = str(g['Visitor']).strip()
        vs  = float(g['Vis Score'])
        hs  = float(g['Home Score'])
        opp = str(g['Home']).strip() if vis == team else vis
        won = (vs > hs) if vis == team else (hs > vs)
        opp_pct = _pct(fpi_ratings.get(opp, 0.0))
        if won:
            score_parts.append(opp_pct)         # win over good team = high value
        else:
            score_parts.append(-(1.0 - opp_pct))  # loss to weak team = big penalty

    return round(sum(score_parts) / len(score_parts), 4) if score_parts else 0.0


def compute_chaos_rating(scores_df, team, year=None, week_cap=None, fpi_ratings=None):
    """
    Chaos Rating — volatility/unpredictability score for a team's season.

    Non-linear MOV scaling gives real variance between a 3-pt upset and a 31-pt blowout upset.
    Ranked opponent bonus makes taking down a top-25 team as an underdog the money moment.
    FCS opponents excluded entirely.

    Scale:  80+ = PURE CHAOS  |  50-79 = VOLATILE  |  25-49 = DISRUPTIVE
            5-24 = WILD CARD  |  <0 = CHOKER
    """
    df = scores_df.copy()
    if year:
        df = df[df['YEAR'].fillna(-1).astype(int) == int(year)]
    if week_cap:
        df = df[df['Week'].fillna(0).astype(int) <= int(week_cap)]
    df = df[df['Status'].astype(str).str.upper() == 'FINAL'].copy()
    df['Vis Score']  = pd.to_numeric(df['Vis Score'],  errors='coerce')
    df['Home Score'] = pd.to_numeric(df['Home Score'], errors='coerce')
    df = df.dropna(subset=['Vis Score', 'Home Score'])

    _FCS_P = {'FCS', 'FCSMW', 'FCSW', 'FCSS', 'FCSE'}

    team_games = df[
        (df['Visitor'].astype(str).str.strip() == team) |
        (df['Home'].astype(str).str.strip()    == team)
    ]
    if team_games.empty:
        return 0.0

    fpi = fpi_ratings or {}
    my_fpi = fpi.get(team, 0.0)
    scores = []

    for _, g in team_games.iterrows():
        vis    = str(g['Visitor']).strip()
        vs     = float(g['Vis Score'])
        hs     = float(g['Home Score'])
        margin = abs(vs - hs)
        is_vis = vis == team
        opp    = str(g['Home']).strip() if is_vis else vis
        won    = (vs > hs) if is_vis else (hs > vs)

        # Skip FCS placeholder teams — meaningless for chaos
        if any(opp.upper().startswith(p) for p in _FCS_P):
            continue

        opp_fpi  = fpi.get(opp, 0.0)
        fpi_gap  = my_fpi - opp_fpi   # positive = I'm favored

        opp_rank_col = 'Home Rank' if is_vis else 'Visitor Rank'
        try:
            opp_ranked = pd.notna(g.get(opp_rank_col)) and int(float(g[opp_rank_col])) <= 25
        except Exception:
            opp_ranked = False

        if won:
            if fpi_gap < -2:
                # Non-linear MOV: (margin/7)^0.65 * 9 gives fractional variance
                # 3pt  upset → ~6pts mov_bonus
                # 14pt upset → ~14pts mov_bonus
                # 35pt upset → ~22pts mov_bonus
                underdog_mag = abs(fpi_gap) * 1.2         # uncapped — real FPI gap matters
                mov_bonus    = (margin / 7.0) ** 0.65 * 9  # fractional power = spread
                ranked_bonus = 20 if opp_ranked else 0     # knocking off a ranked team = big deal
                scores.append(round(12 + underdog_mag + mov_bonus + ranked_bonus, 2))
            elif fpi_gap > 10:
                scores.append(1.0)    # dominant win — expected, boring
            else:
                scores.append(3.0)    # close expected win
        else:
            if fpi_gap > 2:
                # Lost as favorite — penalty scales with how big a favorite you were
                fav_mag          = fpi_gap * 0.8   # uncapped
                unranked_penalty = 12 if not opp_ranked else 0
                scores.append(-(10 + fav_mag + unranked_penalty))
            elif opp_ranked:
                scores.append(-2.0)   # lost to ranked as underdog — expected
            else:
                scores.append(-6.0)   # lost to unranked as underdog

    return round(sum(scores), 1) if scores else 0.0


@st.cache_data(ttl=600)
def build_full_ratings_table(year=None, week_cap=None):
    """
    Build a complete ratings table for all teams with FPI, SOS, SOR, Chaos, record.
    Returns DataFrame sorted by FPI desc. FCS teams excluded.

    """
    target_year = int(year) if year else CURRENT_YEAR
    df = load_scores_master(target_year)
    if df.empty:
        return pd.DataFrame()

    df['YEAR'] = pd.to_numeric(df.get('YEAR'), errors='coerce')
    df['Week'] = pd.to_numeric(df.get('Week'), errors='coerce')

    # Compute FPI first (needed for SOS/SOR)
    fpi = compute_power_ratings(df, year=target_year, week_cap=week_cap)
    if not fpi:
        return pd.DataFrame()

    completed = df[df['Status'].astype(str).str.upper() == 'FINAL'].copy()
    wk = int(week_cap) if week_cap else None

    # FCS placeholder teams to exclude from display
    _FCS_PREFIXES = {'FCS', 'FCSMW', 'FCSW', 'FCSS', 'FCSE'}

    rows = []
    for team in sorted(fpi.keys()):
        # Skip FCS placeholder teams
        if any(str(team).upper().startswith(p) for p in _FCS_PREFIXES):
            continue
        w, l = get_team_record(completed, team, wk)
        sos, opps = compute_sos(df, team, year=target_year, week_cap=wk, fpi_ratings=fpi)
        sor = compute_sor(df, team, year=target_year, week_cap=wk, fpi_ratings=fpi)
        chaos = compute_chaos_rating(df, team, year=target_year, week_cap=wk, fpi_ratings=fpi)
        streak_n, streak_t = get_team_current_streak(completed, team, wk or 99)
        qw, best_rk = get_quality_win_context(completed, team, wk or 99)
        rows.append({
            'Team':        team,
            'W':           w,
            'L':           l,
            'WinPct':      round(w / max(1, w + l), 3),
            'FPI':         fpi[team],
            'SOS':         sos,
            'SOR':         sor,
            'Chaos':       chaos,
            'Streak':      f"{streak_n}{streak_t}" if streak_n else '',
            'QualityWins': qw,
            'BestWin':     f"#{best_rk}" if best_rk else '',
            'GamesPlayed': w + l,
        })

    out = pd.DataFrame(rows).sort_values('FPI', ascending=False).reset_index(drop=True)
    if 'Rank' not in out.columns:
        out.insert(0, 'Rank', range(1, len(out) + 1))
    return out



@st.cache_data(ttl=600)
def compute_ms_plus(year=None, week_cap=None):
    """
    MS+ Ratings — CFB26-tuned composite rating inspired by SP+.
    Returns DataFrame with Team, MSPlus, and component scores.
    """
    target_year = int(year) if year else CURRENT_YEAR

    # ── Load data sources ─────────────────────────────────────────────
    try:
        ratings_df = pd.read_csv('TeamRatingsHistory.csv')
        ratings_df['YEAR'] = pd.to_numeric(ratings_df['YEAR'], errors='coerce')
        ratings_df['TEAM'] = ratings_df['TEAM'].astype(str).str.strip()
    except Exception:
        ratings_df = pd.DataFrame()

    try:
        recruit_df = pd.read_csv('recruiting_class_history_all.csv')
        recruit_df['Year'] = pd.to_numeric(recruit_df.get('Year', recruit_df.get('YEAR', 0)), errors='coerce')
    except Exception:
        recruit_df = pd.DataFrame()

    try:
        # Prefer the new year-keyed top-20 roster file; fall back to full roster
        _top20_file = f'cfb_136_top30_rosters_{target_year}.csv'
        if os.path.exists(_top20_file):
            roster_df = pd.read_csv(_top20_file)
            roster_df['YEAR'] = pd.to_numeric(roster_df.get('YEAR', target_year), errors='coerce')
            roster_df = roster_df[roster_df['YEAR'].fillna(-1).astype(int) == target_year].copy()

            # ── Column rename: watcher writes TEAM/POS/YEAR_CLASS, components expect Team/Pos/Year
            roster_df = roster_df.rename(columns={
                'TEAM':       'Team',
                'POS':        'Pos',
                'YEAR_CLASS': 'Year',
            })

            # ── Team name normalization — GPT sometimes uses full names or mascots
            _team_norm = {
                'University of Nevada, Las Vegas': 'UNLV',
                'University of South Florida':     'USF',
                'University of Southern California': 'USC',
                'University of Texas at San Antonio': 'UTSA',
                'University of Massachusetts':     'Massachusetts',
                'Southern Methodist':              'SMU',
                'Brigham Young':                   'BYU',
                'Pittsburgh Panthers':             'Pittsburgh',
                # Expansion/created dynasty teams — mascot variant → canonical name
                'Alabaster Bulldogs':              'Alabaster',
                'Hammond Carnivores':              'Hammond',
                'Rapid City Stegos':               'Rapid City',
            }
            roster_df['Team'] = roster_df['Team'].map(
                lambda t: _team_norm.get(str(t).strip(), str(t).strip())
            )

            # ── Drop only true FCS placeholders GPT hallucinates — NOT dynasty created teams
            _junk_teams = set()  # no real junk after normalization above
            if _junk_teams:
                roster_df = roster_df[~roster_df['Team'].isin(_junk_teams)].copy()

            # ── Dedup: keep highest-OVR row per (Team, Name, Pos)
            _name_col = 'NAME' if 'NAME' in roster_df.columns else 'Name'
            roster_df = (roster_df
                .sort_values('OVR', ascending=False)
                .drop_duplicates(subset=['Team', _name_col, 'Pos'], keep='first')
                .reset_index(drop=True))

        else:
            roster_df = _load_rosters_full_csv()
            roster_df['Season'] = pd.to_numeric(roster_df.get('Season', roster_df.get('YEAR', target_year)), errors='coerce')
            roster_df = roster_df[roster_df['Season'].fillna(-1).astype(int) == target_year].copy()

        for _rc in ('OVR', 'SPD', 'ACC', 'AGI', 'COD', 'STR', 'AWR'):
            if _rc in roster_df.columns:
                roster_df[_rc] = pd.to_numeric(roster_df[_rc], errors='coerce').fillna(0)
    except Exception:
        roster_df = pd.DataFrame()

    try:
        champs_df = pd.read_csv('champs.csv')
        champs_df['year'] = pd.to_numeric(champs_df.get('year', champs_df.get('Year', 0)), errors='coerce')
    except Exception:
        champs_df = pd.DataFrame()

    try:
        heisman_watch = pd.read_csv('Heisman_watch_history.csv')
        heisman_watch['YEAR'] = pd.to_numeric(heisman_watch.get('YEAR', 0), errors='coerce')
        hw_current = heisman_watch[heisman_watch['YEAR'] == target_year].copy()
        hw_current['RANK'] = pd.to_numeric(hw_current.get('RANK', 99), errors='coerce').fillna(99)
    except Exception:
        hw_current = pd.DataFrame()

    # Get FPI for Clobber Rating component
    fpi_scores = {}
    try:
        _sched = load_scores_master(target_year)
        if not _sched.empty:
            fpi_scores = compute_power_ratings(_sched, year=target_year, week_cap=week_cap)
    except Exception:
        pass

    # Load multi-year schedule for Recent Performance W/L history (last 4 seasons)
    # Priority: schedule_{YEAR}.csv (full league, 2042+) → CPUscores for older years
    _hist_sched = pd.DataFrame()
    try:
        import glob as _glob
        _hist_parts = []
        # Years in range: target_year-4 to target_year-1
        for _hy in range(target_year - 4, target_year):
            _sf = f'schedule_{_hy}.csv'
            if os.path.exists(_sf):
                # schedule_{YEAR}.csv — full league, preferred
                _hp = pd.read_csv(_sf)
                _hp['YEAR'] = _hy
                _hist_parts.append(_hp)
            else:
                # Fall back to CPUscores year file (user teams only pre-2042)
                _cf = f'CPUscores_MASTER_{_hy}.csv'
                if os.path.exists(_cf):
                    _hp = pd.read_csv(_cf)
                    _hp['YEAR'] = _hy
                    _hist_parts.append(_hp)
        # Also check legacy CPUscores_MASTER.csv for any years not covered above
        if os.path.exists('CPUscores_MASTER.csv'):
            _legacy = pd.read_csv('CPUscores_MASTER.csv')
            if 'YEAR' in _legacy.columns:
                _legacy['YEAR'] = pd.to_numeric(_legacy['YEAR'], errors='coerce')
                _legacy = _legacy[
                    (_legacy['YEAR'] >= target_year - 4) &
                    (_legacy['YEAR'] <  target_year)
                ]
                # Only append years not already covered by schedule_ files
                _covered_years = {int(_hp['YEAR'].iloc[0]) for _hp in _hist_parts if not _hp.empty and 'YEAR' in _hp.columns}
                _legacy = _legacy[~_legacy['YEAR'].isin(_covered_years)]
                if not _legacy.empty:
                    _hist_parts.append(_legacy)

        if _hist_parts:
            _hist_sched = pd.concat(_hist_parts, ignore_index=True)
            _hist_sched['YEAR'] = pd.to_numeric(_hist_sched.get('YEAR', target_year), errors='coerce')
            _hist_sched['Vis Score']  = pd.to_numeric(_hist_sched.get('Vis Score', 0),  errors='coerce')
            _hist_sched['Home Score'] = pd.to_numeric(_hist_sched.get('Home Score', 0), errors='coerce')
            # Only completed games
            _status_col = next((c for c in ('Status','STATUS') if c in _hist_sched.columns), None)
            if _status_col:
                _hist_sched = _hist_sched[
                    _hist_sched[_status_col].astype(str).str.upper() == 'FINAL'
                ].copy()
            _hist_sched = _hist_sched.reset_index(drop=True)
    except Exception:
        _hist_sched = pd.DataFrame()

    # Build team list from ratings
    if ratings_df.empty:
        return pd.DataFrame()
    yr_ratings = ratings_df[ratings_df['YEAR'].fillna(-1).astype(int) == target_year].copy()
    if yr_ratings.empty:
        yr_ratings = ratings_df[ratings_df['YEAR'].fillna(-1).astype(int) == target_year - 1].copy()
    if yr_ratings.empty:
        return pd.DataFrame()

    ratings_teams = yr_ratings['TEAM'].dropna().unique().tolist()

    # If TeamRatingsHistory only has user teams (sparse, < 20 entries),
    # supplement from schedule_{YEAR}.csv so MS+ covers the full field.
    _sched_teams = set()
    try:
        _sm = load_scores_master(target_year)
        if not _sm.empty:
            for _col in ('Visitor', 'Home', 'VISITOR', 'HOME'):
                if _col in _sm.columns:
                    _sched_teams.update(
                        _sm[_col].dropna().astype(str).str.strip().tolist()
                    )
    except Exception:
        pass

    if len(ratings_teams) < 20 and _sched_teams:
        # Sparse — build from full schedule, ratings_teams values take priority in loop
        all_teams = sorted(set(ratings_teams) | _sched_teams)
    else:
        all_teams = ratings_teams

    # Veteran presence mean (league-wide 86+ JR/SR OVR) for relative comparison
    _VET_YEARS = {'JR','JR (RS)','SR','SR (RS)','JR(RS)','SR(RS)'}
    vet_mean = 0.0
    if not roster_df.empty and 'Year' in roster_df.columns:
        _vet_all = roster_df[
            (roster_df['OVR'] >= 86) &
            (roster_df['Year'].astype(str).str.strip().str.upper().isin({y.upper() for y in _VET_YEARS}))
        ]
        vet_mean = _vet_all['OVR'].mean() if not _vet_all.empty else 86.0

    rows = []
    for team in all_teams:
        team = str(team).strip()
        components = {}

        # ── 1. Team Ratings (OVR, OFF, DEF) — weight 0.20 ────────────
        tr = yr_ratings[yr_ratings['TEAM'] == team]
        if not tr.empty:
            r0 = tr.iloc[0]
            t_ovr = safe_num(r0.get('OVERALL', r0.get('OVR', 75)), 75)
            t_off = safe_num(r0.get('OFFENSE', r0.get('OFF', 75)), 75)
            t_def = safe_num(r0.get('DEFENSE', r0.get('DEF', 75)), 75)
        else:
            t_ovr = t_off = t_def = 75.0
        components['ratings'] = round((t_ovr * 0.5 + t_off * 0.25 + t_def * 0.25 - 70) / 30 * 100, 1)

        # ── 2. Recruiting Pipeline (last 4 class ranks) — weight 0.15 ─
        # Use OVERALL class rank only — avoids mixing HS/Transfer ranks with overall rank
        rec_score = None
        if not recruit_df.empty and 'Team' in recruit_df.columns and 'Rank' in recruit_df.columns:
            _rc = recruit_df[
                (recruit_df['Team'].astype(str).str.strip() == team) &
                (recruit_df['Year'] >= target_year - 4) &
                (recruit_df['Year'] < target_year)
            ].copy()
            # Prefer OVERALL rank; fall back to any ClassType if OVERALL not present
            if 'ClassType' in _rc.columns:
                _rc_overall = _rc[_rc['ClassType'].astype(str).str.upper() == 'OVERALL'].copy()
                if not _rc_overall.empty:
                    _rc = _rc_overall
            _rc['Rank'] = pd.to_numeric(_rc['Rank'], errors='coerce')
            if not _rc.empty:
                avg_rk = _rc['Rank'].dropna().mean()
                rec_score = max(0, min(100, round((130 - avg_rk) / 130 * 100, 1)))
        if rec_score is None:
            # No recruiting history — proxy from team OVR
            rec_score = max(0, min(100, round((t_ovr - 70) / 30 * 100, 1)))
        components['recruiting'] = rec_score
        xfer_score = 50.0
        if not recruit_df.empty and 'ClassType' in recruit_df.columns:
            _xf = recruit_df[
                (recruit_df['Team'].astype(str).str.strip() == team) &
                (recruit_df['Year'] >= target_year - 4) &
                (recruit_df['Year'] < target_year) &
                (recruit_df['ClassType'].astype(str).str.upper().isin({'TRANSFER','PORTAL'}))
            ].copy()
            if not _xf.empty and 'Rank' in _xf.columns:
                _xf['Rank'] = pd.to_numeric(_xf['Rank'], errors='coerce')
                avg_xf = _xf['Rank'].dropna().mean()
                xfer_score = max(0, min(100, round((130 - avg_xf) / 130 * 100, 1)))
        components['transfer'] = xfer_score

        # ── 4. Veteran Presence (86+ OVR JR/SR) — weight 0.10 ────────
        vet_score = 50.0
        if not roster_df.empty and 'Team' in roster_df.columns and 'Year' in roster_df.columns:
            _tv = roster_df[
                (roster_df['Team'].astype(str).str.strip() == team) &
                (roster_df['OVR'] >= 86) &
                (roster_df['Year'].astype(str).str.strip().str.upper().isin({y.upper() for y in _VET_YEARS}))
            ]
            if not _tv.empty:
                team_vet_avg = _tv['OVR'].mean()
                vet_score = min(100, max(0, 50 + (team_vet_avg - vet_mean) * 5))
                vet_score = round(vet_score + len(_tv) * 0.5, 1)  # bonus for depth
        components['veteran'] = min(100, vet_score)

        # ── 5. Starting Speed (90+ SPD at JR/SR level) — weight 0.07 ─
        spd_score = 50.0
        if not roster_df.empty and 'Team' in roster_df.columns:
            _ts = roster_df[
                (roster_df['Team'].astype(str).str.strip() == team) &
                (roster_df['SPD'] >= 90) &
                (roster_df['Year'].astype(str).str.strip().str.upper().isin({y.upper() for y in _VET_YEARS}))
            ]
            spd_score = min(100, 50 + len(_ts) * 4)
        components['speed'] = spd_score

        # ── 6. Captain of the Ship (QB rating) — weight 0.12 ─────────
        qb_score = 50.0
        if not roster_df.empty and 'Pos' in roster_df.columns:
            _qbs = roster_df[
                (roster_df['Team'].astype(str).str.strip() == team) &
                (roster_df['Pos'].astype(str).str.upper().isin({'QB'}))
            ].sort_values('OVR', ascending=False)
            if not _qbs.empty:
                _qb1 = _qbs.iloc[0]
                _qb_ovr = float(_qb1.get('OVR', 75))
                _qb_spd = float(_qb1.get('SPD', 75))
                _qb_acc = float(_qb1.get('ACC', 75))
                if _qb_ovr >= 91:
                    qb_score = 90.0
                elif _qb_ovr >= 85:
                    qb_score = 70.0
                elif _qb_ovr >= 80:
                    qb_score = 55.0
                else:
                    qb_score = 35.0
                # Dual-threat bonus
                if _qb_spd >= 88 and _qb_acc >= 85:
                    qb_score = min(100, qb_score + 10)
        components['qb'] = qb_score

        # ── 7. Recent Performance (last 4 seasons) — weight 0.10 ──────
        # Blends: titles (natty +15, conf +8) + win rate from schedule history
        perf_score = 50.0

        # Title component — from champs.csv
        natty_count = 0
        conf_count  = 0
        if not champs_df.empty and 'Team' in champs_df.columns:
            _cp = champs_df[
                (champs_df['Team'].astype(str).str.strip() == team) &
                (champs_df['year'] >= target_year - 4) &
                (champs_df['year'] <  target_year)
            ]
            if not _cp.empty:
                _type_col = 'type' if 'type' in _cp.columns else ('Type' if 'Type' in _cp.columns else None)
                if _type_col:
                    natty_count = len(_cp[_cp[_type_col].astype(str).str.upper().str.contains('NATTY|NATIONAL', na=False)])
                    conf_count  = len(_cp[_cp[_type_col].astype(str).str.upper().str.contains('CONF', na=False)])
        title_boost = natty_count * 15 + conf_count * 8

        # Win rate component — only fires when schedule_{YEAR}.csv files exist in the lookback window.
        # This ensures CPU and user teams are always on equal footing:
        # - Season 2042: no schedule_ history yet → everyone gets neutral 50
        # - Season 2043+: schedule_2042.csv in window → all 136 teams get real win rates
        win_rate_score = 50.0
        _has_schedule_history = any(
            os.path.exists(f'schedule_{_hy}.csv')
            for _hy in range(target_year - 4, target_year)
        )
        if _has_schedule_history and not _hist_sched.empty:
            _vis_col = next((c for c in ('Visitor','VISITOR','visitor') if c in _hist_sched.columns), None)
            _hom_col = next((c for c in ('Home','HOME','home')         if c in _hist_sched.columns), None)
            if _vis_col and _hom_col:
                _tm_games = _hist_sched[
                    (_hist_sched[_vis_col].astype(str).str.strip() == team) |
                    (_hist_sched[_hom_col].astype(str).str.strip() == team)
                ]
                if not _tm_games.empty:
                    _wins = 0
                    for _, _g in _tm_games.iterrows():
                        _vs = float(_g.get('Vis Score', 0) or 0)
                        _hs = float(_g.get('Home Score', 0) or 0)
                        _is_vis = str(_g.get(_vis_col, '')).strip() == team
                        _won = (_vs > _hs) if _is_vis else (_hs > _vs)
                        if _won: _wins += 1
                    _win_pct = _wins / len(_tm_games)
                    win_rate_score = max(0, min(100, round((_win_pct - 0.200) / 0.600 * 100, 1)))

        # Blend: 60% win rate, 40% titles
        perf_score = min(100, round(win_rate_score * 0.60 + (50 + title_boost) * 0.40, 1))
        components['performance'] = perf_score

        # ── 8. Clobber Rating (FPI) — weight 0.08 ────────────────────
        fpi_val = fpi_scores.get(team, None)
        if fpi_val is not None and fpi_scores:
            all_fpi   = list(fpi_scores.values())
            fpi_mean  = sum(all_fpi) / len(all_fpi)
            fpi_stdev = max((sum((x - fpi_mean)**2 for x in all_fpi) / len(all_fpi))**0.5, 1)
            clobber   = round(50 + (fpi_val - fpi_mean) / fpi_stdev * 15, 1)
            clobber   = max(0, min(100, clobber))
        else:
            clobber = 50.0
        components['clobber'] = clobber

        # ── 8b. Chaos Rating — weight 0.03 ───────────────────────────
        try:
            _chaos_sched = load_scores_master(target_year)
            raw_chaos = compute_chaos_rating(
                _chaos_sched, team, year=target_year,
                week_cap=week_cap, fpi_ratings=fpi_scores
            )
        except Exception:
            raw_chaos = 0.0
        chaos_score = max(0, min(100, round(50 + raw_chaos * 1.5, 1)))
        components['chaos'] = chaos_score

        # ── 9. Generational Talent — weight 0.05 ─────────────────────
        # A player qualifies if OVR >= 90 AND at least 2 of these are >= 95:
        #   Speed (SPD), Acceleration (ACC), Agility (AGI), Change of Direction (COD)
        gen_score = 50.0
        if not roster_df.empty and 'Team' in roster_df.columns:
            _candidates = roster_df[
                (roster_df['Team'].astype(str).str.strip() == team) &
                (roster_df['OVR'] >= 90)
            ].copy()
            def _is_generational(r):
                attrs = [
                    float(r.get('SPD', 0) or 0),
                    float(r.get('ACC', 0) or 0),
                    float(r.get('AGI', 0) or 0),
                    float(r.get('COD', 0) or 0),
                ]
                return sum(1 for a in attrs if a >= 95) >= 2
            _gen_count = _candidates.apply(_is_generational, axis=1).sum() if not _candidates.empty else 0
            gen_score = min(100, 50 + int(_gen_count) * 12)
        components['generational'] = round(gen_score, 1)

        # ── 10. Heisman Hopeful — weight 0.02 ────────────────────────
        hh_score = 50.0
        if not hw_current.empty and 'TEAM' in hw_current.columns:
            _hh = hw_current[hw_current['TEAM'].astype(str).str.strip() == team]
            top5 = _hh[_hh['RANK'] <= 5]
            if len(top5) >= 2:
                hh_score = 100.0
            elif len(top5) == 1:
                hh_score = 80.0
            elif not _hh.empty:
                hh_score = 65.0
        components['heisman'] = hh_score

        # ── Composite MS+ score ───────────────────────────────────────
        # Weights total = 1.00
        weights = {
            'ratings': 0.20, 'recruiting': 0.15, 'transfer': 0.08,
            'veteran': 0.10, 'speed': 0.07,      'qb': 0.12,
            'performance': 0.10, 'clobber': 0.08,
            'generational': 0.05, 'heisman': 0.02, 'chaos': 0.03,
        }
        ms_plus = sum(components.get(k, 50) * v for k, v in weights.items())
        ms_plus = round(ms_plus, 1)

        # Get FPI data to include in same row
        fpi_rk_row = {}
        rows.append({
            'Team': team,
            'MSPlus': ms_plus,
            **{f'_{k}': v for k, v in components.items()},
        })

    if not rows:
        return pd.DataFrame()

    msp_df = pd.DataFrame(rows).sort_values('MSPlus', ascending=False).reset_index(drop=True)
    # FPI/SOS/SOR columns are intentionally NOT merged here.
    # Use get_ratings_and_ms_plus() at render sites so FPI is computed once and shared.
    for _c in ['W','L','FPI','SOS','SOR','QualityWins']:
        msp_df[_c] = 0.0
    msp_df['Streak']  = ''
    msp_df['BestWin'] = ''
    return msp_df


def get_ratings_and_ms_plus(year=None, week_cap=None):
    """
    Returns (fpi_df, msp_df) — reads from pre-computed CSVs on first boot if available,
    falls back to live computation otherwise.

    Pre-computed files (written by COMPUTE_RATINGS.bat):
      FPI/fpi_ratings_{YEAR}_wk{WEEK}.csv  — FPI/SOS/SOR table
      FPI/ms_plus_{YEAR}_wk{WEEK}.csv      — MS+ component table

    Falls back to repo root for backwards compatibility if FPI/ subfolder not found.
    If no pre-computed file exists, computes live (slow on first boot).
    """
    target_year = int(year) if year else CURRENT_YEAR
    wk          = int(week_cap) if week_cap else CURRENT_WEEK_NUMBER

    base_name_fpi = f'fpi_ratings_{target_year}_wk{wk}.csv'
    base_name_msp = f'ms_plus_{target_year}_wk{wk}.csv'

    # Check FPI/ subfolder first, then root fallback
    def _find_file(base_name):
        subfolder = os.path.join('FPI', base_name)
        if os.path.exists(subfolder):
            return subfolder
        if os.path.exists(base_name):
            return base_name
        return None

    fpi_path = _find_file(base_name_fpi)
    msp_path = _find_file(base_name_msp)

    fpi_df = pd.DataFrame()
    msp_df = pd.DataFrame()

    if fpi_path:
        try:
            fpi_df = pd.read_csv(fpi_path)
        except Exception:
            fpi_df = pd.DataFrame()

    if msp_path:
        try:
            msp_df = pd.read_csv(msp_path)
        except Exception:
            msp_df = pd.DataFrame()

    # ── Fall back to live computation if CSVs missing ─────────────────
    if fpi_df.empty:
        fpi_df = build_full_ratings_table(year=year, week_cap=week_cap)
    if msp_df.empty:
        msp_df = compute_ms_plus(year=year, week_cap=week_cap)

    # ── Merge FPI columns into MS+ df ─────────────────────────────────
    if not fpi_df.empty and not msp_df.empty:
        try:
            _fpi_cols = ['Team','W','L','FPI','SOS','SOR','Chaos','Streak','QualityWins','BestWin']
            _fpi_slim = fpi_df[[c for c in _fpi_cols if c in fpi_df.columns]].copy()
            msp_df = msp_df.drop(
                columns=[c for c in ['W','L','FPI','SOS','SOR','Chaos','Streak','QualityWins','BestWin']
                         if c in msp_df.columns],
                errors='ignore'
            )
            msp_df = msp_df.merge(_fpi_slim, on='Team', how='left')
            for _c in ['W','L','FPI','SOS','SOR','Chaos','QualityWins']:
                if _c in msp_df.columns:
                    msp_df[_c] = pd.to_numeric(msp_df[_c], errors='coerce').fillna(0)
            for _c in ['Streak','BestWin']:
                if _c in msp_df.columns:
                    msp_df[_c] = msp_df[_c].fillna('')
        except Exception:
            pass

    return fpi_df, msp_df


def infer_best_fun_stat(y_data):
    if y_data.empty:
        return "No games found for that season."

    closest = y_data[y_data['Margin'] == y_data['Margin'].min()].iloc[0]
    highest_scoring = y_data[y_data['Total Points'] == y_data['Total Points'].max()].iloc[0]
    blowout = y_data[y_data['Margin'] == y_data['Margin'].max()].iloc[0]

    options = [
        f"Closest game: {closest['Visitor_Final']} vs {closest['Home_Final']} ended with just a {int(closest['Margin'])}-point margin.",
        f"Track meet alert: {highest_scoring['Visitor_Final']} vs {highest_scoring['Home_Final']} combined for {int(highest_scoring['Total Points'])} points.",
        f"Beatdown of the year: {blowout['Winner_Team']} handled business by {int(blowout['Margin'])}."
    ]

    avg_margin = y_data['Margin'].mean()
    if avg_margin <= 7:
        options.append("The whole season played like a knife fight. Average margin was under one score.")
    elif avg_margin >= 20:
        options.append("A lot of Saturdays turned into statements. Average margin cleared 20 points.")

    return options[len(y_data) % len(options)]


def tier_from_dynasty_score(score):
    if score >= 650:
        return "Blue Blood"
    if score >= 450:
        return "Contender"
    if score >= 250:
        return "Builder"
    return "Upstart"


def _recent_recruit_window(row, anchor_year=None, lookback=4):
    if anchor_year is None:
        anchor_year = CURRENT_YEAR
    year_cols = sorted([int(c) for c in row.index if str(c).isdigit()])
    vals = []
    for y in year_cols:
        if y <= anchor_year:
            v = clean_rank_value(row.get(str(y)))
            if not pd.isna(v):
                vals.append((y, float(v)))
    if not vals:
        return [], np.nan, 0.0
    vals = vals[-lookback:]
    ranks = [v for _, v in vals]
    weights = np.linspace(1, len(ranks), len(ranks))
    weighted_avg = float(np.average(ranks, weights=weights))
    trend = float(ranks[0] - ranks[-1]) if len(ranks) >= 2 else 0.0
    return vals, weighted_avg, trend


def _recruit_class_tier(weighted_rank, heat_index, bcr):
    if pd.isna(weighted_rank):
        return "No Read"
    if weighted_rank <= 5 or (heat_index >= 88 and bcr >= 55):
        return "Dynasty Class"
    if weighted_rank <= 12 or heat_index >= 80:
        return "Elite Haul"
    if weighted_rank <= 25 or heat_index >= 72:
        return "Strong Class"
    if weighted_rank <= 40 or heat_index >= 62:
        return "Solid Build"
    if weighted_rank <= 65:
        return "Mid Pack"
    return "Needs Bags"


def _recruit_trajectory(row):
    heat = float(row.get('Heat Index', 50))
    pipeline = float(row.get('Pipeline Score', 50))
    speed = float(row.get('Speed Recruiter Index', 50))
    bcr = float(row.get('Blue Chip %', 0))
    if heat >= 84 and pipeline >= 82 and bcr >= 55:
        return "Death Star Loading"
    if heat >= 78 and speed >= 75:
        return "Track Team With Bags"
    if pipeline >= 76:
        return "Roster Machine"
    if heat >= 70 and bcr < 40:
        return "Stars Without Bulk"
    if speed >= 72 and heat < 68:
        return "Speed Lab"
    if heat < 55 and pipeline < 58:
        return "Fraud Watch"
    return "On Schedule"


def _recruit_blurb(row):
    team = row['TEAM']
    tier = row['Class Tier']
    traj = row['Trajectory']
    heat = float(row['Heat Index'])
    bcr = float(row['Blue Chip %'])
    speed = float(row['Speed Recruiter Index'])
    if tier == 'Dynasty Class':
        return f"{team} is recruiting like somebody found the NIL nuke button. This class has full-on dynasty stink on it."
    if traj == 'Track Team With Bags':
        return f"{team} is signing speed freaks and doing it with zero shame. This is less roster building and more a felony footrace."
    if traj == 'Stars Without Bulk':
        return f"{team} keeps landing names, but the blue-chip body count still says somebody forgot the damn trench warfare."
    if traj == 'Fraud Watch':
        return f"{team} is recruiting like the fax machine, the group chat, and the head coach's judgment all failed at once."
    if heat >= 75 and bcr >= 50:
        return f"{team} is stacking a nasty little class. Not all glitz, but enough juice to make the future deeply annoying for everybody else."
    if speed >= 72:
        return f"{team} may not own the whole blue-chip galaxy, but they are absolutely recruiting like speed is a controlled substance."
    return f"{team} is putting together a respectable class. Nothing to start a parade over yet, but definitely not clown shoes either."


def build_recruiting_board(rec_df, model_df, anchor_year=None):
    if anchor_year is None:
        anchor_year = CURRENT_YEAR
    rows = []
    rec_local = rec_df.copy()
    rec_local['USER'] = rec_local['USER'].astype(str).str.strip().str.title()
    if 'Teams' in rec_local.columns:
        rec_local['Teams'] = rec_local['Teams'].astype(str).str.strip()

    for _, m in model_df.iterrows():
        user = str(m['USER']).strip().title()
        team = str(m['TEAM']).strip()
        match = rec_local[(rec_local['USER'] == user) & (rec_local['Teams'].astype(str).str.lower() == team.lower())]
        if match.empty:
            match = rec_local[rec_local['Teams'].astype(str).str.lower() == team.lower()]
        if match.empty:
            match = rec_local[rec_local['USER'] == user]
        rec_row = match.iloc[-1] if not match.empty else pd.Series(dtype=object)

        recent_vals, weighted_rank, trend = _recent_recruit_window(rec_row, anchor_year=anchor_year, lookback=4) if not match.empty else ([], np.nan, 0.0)
        recent_display = ' | '.join([f"{y}:{int(v)}" for y, v in recent_vals]) if recent_vals else 'No recent class data'
        heat = round(max(1.0, min(100.0, 101 - weighted_rank)), 1) if not pd.isna(weighted_rank) else 50.0
        blue = round(float(pd.to_numeric(m.get('BCR_Val', 0), errors='coerce') or 0.0), 1)
        pipeline = round(
            heat * 0.34
            + blue * 0.26
            + float(m.get('Team Speed Score', 0)) * 0.16
            + float(m.get('OVERALL', 0)) * 0.12
            + max(trend, 0) * 1.8
            + float(m.get('Generational (96+ speed or 96+ Acceleration)', 0)) * 2.8,
            1
        )
        speed_idx = round(
            heat * 0.22
            + float(m.get('Team Speed Score', 0)) * 0.34
            + float(m.get('Off Speed (90+ speed)', 0)) * 1.0
            + float(m.get('Def Speed (90+ speed)', 0)) * 1.0
            + float(m.get('Quad 90 (90+ SPD, ACC, AGI & COD)', 0)) * 2.0
            + float(m.get('Generational (96+ speed or 96+ Acceleration)', 0)) * 4.0,
            1
        )
        row = {
            'USER': user,
            'TEAM': team,
            'Logo': get_logo_source(team),
            'Recent Cycle': recent_display,
            'Weighted Avg Rank': round(weighted_rank, 1) if not pd.isna(weighted_rank) else np.nan,
            'Trend Score': round(trend, 1),
            'Heat Index': heat,
            'Blue Chip %': blue,
            'Pipeline Score': pipeline,
            'Speed Recruiter Index': speed_idx,
            'Current Recruiting Score': heat,
            'Current Blue Chip Ratio': round(blue / 100.0, 3),
        }
        row['Class Tier'] = _recruit_class_tier(row['Weighted Avg Rank'], heat, blue)
        row['Trajectory'] = _recruit_trajectory(row)
        row['Recruiting Blurb'] = _recruit_blurb(row)
        rows.append(row)

    out = pd.DataFrame(rows).sort_values(['Heat Index', 'Pipeline Score', 'Speed Recruiter Index'], ascending=False).reset_index(drop=True)
    if not out.empty:
        out['Rank'] = np.arange(1, len(out) + 1)
    return out


def render_recruiting_table(df):
    rows_html = []
    for _, row in df.iterrows():
        team = str(row.get('TEAM', ''))
        user = str(row.get('USER', ''))
        primary = get_team_primary_color(team)
        logo_path = get_logo_source(team)
        logo_uri = image_file_to_data_uri(logo_path)
        logo_html = f"<img src='{logo_uri}' style='width:38px;height:38px;object-fit:contain;'/>" if logo_uri else "<div style='font-size:22px;'>🏈</div>"
        cells = [f"""
        <td style="padding:10px 12px;border-bottom:1px solid #e5e7eb;white-space:nowrap;">
          <div class="isp-flex-row">
            <div style="font-weight:800;min-width:24px;text-align:center;">#{int(row.get('Projected Seed Display', 0))}</div>
            <div style="width:40px;text-align:center;">{logo_html}</div>
            <div>
              <div style="font-weight:800;color:{primary};">{html.escape(team)}</div>
              <div style="font-size:12px;color:#cbd5e1;">{html.escape(user)}</div>
            </div>
          </div>
        </td>
        """]
        vals = [
            html.escape(str(row.get('Recent Cycle', '—'))),
            f"{float(row.get('Weighted Avg Rank', 0)):.1f}" if not pd.isna(row.get('Weighted Avg Rank', np.nan)) else '—',
            f"{float(row.get('Heat Index', 0)):.1f}",
            f"{float(row.get('Pipeline Score', 0)):.1f}",
            f"{float(row.get('Speed Recruiter Index', 0)):.1f}",
            f"{float(row.get('Blue Chip %', 0)):.1f}%",
            html.escape(str(row.get('Class Tier', '—'))),
            html.escape(str(row.get('Trajectory', '—'))),
            html.escape(str(row.get('Recruiting Blurb', '—'))),
        ]
        for disp in vals:
            cells.append(f"<td style='padding:10px 12px;border-bottom:1px solid #e5e7eb;text-align:center;white-space:nowrap;'>{disp}</td>")
        rows_html.append(f"<tr style='border-left:6px solid {primary};background:linear-gradient(90deg,{primary}12,transparent 14%);'>{''.join(cells)}</tr>")
    table_html = f"""
    <div style="overflow-x:auto;border:1px solid #e5e7eb;border-radius:14px;">
      <table class="isp-table">
        <thead>
          <tr style="background:#f8fafc;color:#111827;">
            <th class="isp-th-light isp-th-left">Recruiting Board</th>
            <th class="isp-th-light">Recent Classes</th>
            <th class="isp-th-light">Weighted Avg Rank</th>
            <th class="isp-th-light">Heat Index</th>
            <th class="isp-th-light">Pipeline Score</th>
            <th class="isp-th-light">Speed Recruiter</th>
            <th class="isp-th-light">Blue Chip</th>
            <th class="isp-th-light">Class Tier</th>
            <th class="isp-th-light">Trajectory</th>
            <th class="isp-th-light">Notes</th>
          </tr>
        </thead>
        <tbody>{''.join(rows_html)}</tbody>
      </table>
    </div>
    """
    st.markdown(table_html, unsafe_allow_html=True)


def format_ranked_team_name(team, rank_map):
    team = str(team).strip()
    rank = rank_map.get(team)
    return f"#{int(rank)} {team}" if rank is not None and not pd.isna(rank) else team


def estimate_game_line(team, opp, model_df, rank_map):
    model_local = model_df.copy()
    lookup = model_local.drop_duplicates('TEAM').set_index('TEAM')
    team_pi = float(lookup.loc[team]['Power Index']) if team in lookup.index else 200.0
    opp_pi = float(lookup.loc[opp]['Power Index']) if opp in lookup.index else 200.0
    team_rank = rank_map.get(team)
    opp_rank = rank_map.get(opp)
    team_rank_boost = max(0, 26 - float(team_rank)) * 0.85 if team_rank is not None and not pd.isna(team_rank) else 0.0
    opp_rank_boost = max(0, 26 - float(opp_rank)) * 0.85 if opp_rank is not None and not pd.isna(opp_rank) else 0.0
    diff = (team_pi + team_rank_boost) - (opp_pi + opp_rank_boost)
    line = round(abs(diff) / 6.8, 1)
    if abs(diff) < 2.5:
        return "Pick'em", None
    favored = team if diff > 0 else opp
    return f"{favored} -{line}", favored


def estimate_game_line_from_ratings(home_team, away_team, ratings_map, home_field=True):
    """
    Compute betting line using OVR/OFF/DEF ratings from team_ratings.csv.
    ratings_map: dict of team → {'OVR': x, 'OFF': x, 'DEF': x}
    Returns (line_str, favored_team, spread_value) or None if ratings missing.
    home_field: True adds ~2.5pt HFA to home team.
    """
    _DEFAULT_R = {'OVR': 82, 'OFF': 82, 'DEF': 82}
    hr = ratings_map.get(str(home_team).strip().lower()) or _DEFAULT_R
    ar = ratings_map.get(str(away_team).strip().lower()) or _DEFAULT_R
    try:
        h_ovr = float(hr.get('OVR', hr.get('OVERALL', 82)) or 82)
        h_off = float(hr.get('OFF', hr.get('OFFENSE', 82)) or 82)
        h_def = float(hr.get('DEF', hr.get('DEFENSE', 82)) or 82)
        a_ovr = float(ar.get('OVR', ar.get('OVERALL', 82)) or 82)
        a_off = float(ar.get('OFF', ar.get('OFFENSE', 82)) or 82)
        a_def = float(ar.get('DEF', ar.get('DEFENSE', 82)) or 82)
    except Exception:
        return None
    if h_ovr == 0 and a_ovr == 0:
        return None
    h_score = (h_off * 0.55 + (100 - a_def) * 0.45) * 0.32 + 7
    a_score = (a_off * 0.55 + (100 - h_def) * 0.45) * 0.32 + 7
    hfa = 2.5 if home_field else 0
    diff = (h_score + hfa) - a_score
    # Guard against NaN propagation from perf_map
    if not (isinstance(diff, float) and diff != diff):
        pass  # diff is valid
    else:
        diff = 0.0  # NaN → treat as Pick'em
    spread = round(abs(diff) * 10) / 10
    if spread < 1.0:
        return "Pick'em"  # string, not tuple — avoids conditional logic bug
    favored = home_team if diff > 0 else away_team
    spread_str = f"{spread:.1f}" if spread % 1 != 0 else f"{int(spread)}"
    return f"{favored} -{spread_str}", favored, diff


def normalize_game_summaries(df):
    """
    Normalize game_summaries.csv column names from watcher format to app format.

    The watcher writes: VISITOR, HOME, VIS_FINAL, HOME_FINAL, VIS_Q1..VIS_Q4,
    HOME_Q1..HOME_Q4, VIS_OT, HOME_OT, VIS_PASS_YDS, HOME_PASS_YDS,
    VIS_RUSH_YDS, HOME_RUSH_YDS, VIS_TURNOVERS, HOME_TURNOVERS, etc.

    The app's candidate lookup lists expect the names in the right-hand column below.
    Calling this once after read_csv makes all lookups work without touching them.
    """
    if df is None or df.empty:
        return df
    rename_map = {
        # Team names
        'VISITOR':          'Visitor',
        'HOME':             'Home',
        # Final scores
        'VIS_FINAL':        'VisitorScore',
        'HOME_FINAL':       'HomeScore',
        # Quarter scores — visitor
        'VIS_Q1':           'Q1_Visitor',
        'VIS_Q2':           'Q2_Visitor',
        'VIS_Q3':           'Q3_Visitor',
        'VIS_Q4':           'Q4_Visitor',
        'VIS_OT':           'Visitor_OT',
        # Quarter scores — home
        'HOME_Q1':          'Q1_Home',
        'HOME_Q2':          'Q2_Home',
        'HOME_Q3':          'Q3_Home',
        'HOME_Q4':          'Q4_Home',
        'HOME_OT':          'Home_OT',
        # Passing yards
        'VIS_PASS_YDS':     'PassYds_Visitor',
        'HOME_PASS_YDS':    'PassYds_Home',
        # Rushing yards
        'VIS_RUSH_YDS':     'RushYds_Visitor',
        'HOME_RUSH_YDS':    'RushYds_Home',
        # Turnovers
        'VIS_TURNOVERS':    'Turnovers_Visitor',
        'HOME_TURNOVERS':   'Turnovers_Home',
        # User columns
        'VIS_USER':         'Vis_User',
        'HOME_USER':        'Home_User',
        # Ranks
        'VIS_RANK':         'Visitor Rank',
        'HOME_RANK':        'Home Rank',
    }
    # Only rename columns that actually exist — safe for any schema variant
    actual_renames = {k: v for k, v in rename_map.items() if k in df.columns and v not in df.columns}
    if actual_renames:
        df = df.rename(columns=actual_renames)
    return df


def load_team_ratings(year=None):
    """
    Load team ratings. Prefers team_ratings_{YEAR}.csv (new year-keyed format),
    falls back to legacy team_ratings.csv.
    Returns dict: team_name.lower() → {'OVR': x, 'OFF': x, 'DEF': x}
    """
    target_year = int(year) if year else CURRENT_YEAR

    # Try year-keyed file first
    _yr_file = f'team_ratings_{target_year}.csv'
    if os.path.exists(_yr_file):
        try:
            tr = pd.read_csv(_yr_file)
            result = {}
            for _, row in tr.iterrows():
                k = str(row.get('TEAM', '')).strip().lower()
                if not k: continue
                result[k] = {
                    'OVR': row.get('OVR', row.get('OVERALL', 82)),
                    'OFF': row.get('OFF', row.get('OFFENSE', 82)),
                    'DEF': row.get('DEF', row.get('DEFENSE', 82)),
                }
            if result:
                return result
        except Exception:
            pass

    # Fall back to legacy team_ratings.csv (multi-year flat file)
    try:
        tr = pd.read_csv('team_ratings.csv')
        tr['YEAR'] = pd.to_numeric(tr['YEAR'], errors='coerce')
        result = {}
        if year is not None:
            # First pass: all historical data (oldest first) gives CPU teams
            all_sorted = tr.sort_values('YEAR', ascending=True)
            for _, row in all_sorted.iterrows():
                k = str(row['TEAM']).strip().lower()
                result[k] = {
                    'OVR': row.get('OVR', row.get('OVERALL')),
                    'OFF': row.get('OFF', row.get('OFFENSE')),
                    'DEF': row.get('DEF', row.get('DEFENSE')),
                }
            # Second pass: exact year overwrites so user teams are current
            yr_data = tr[tr['YEAR'] == int(year)]
            if yr_data.empty:
                yr_data = tr[tr['YEAR'] == tr['YEAR'].max()]
            for _, row in yr_data.iterrows():
                k = str(row['TEAM']).strip().lower()
                result[k] = {
                    'OVR': row.get('OVR', row.get('OVERALL')),
                    'OFF': row.get('OFF', row.get('OFFENSE')),
                    'DEF': row.get('DEF', row.get('DEFENSE')),
                }
        else:
            yr_data = tr[tr['YEAR'] == tr['YEAR'].max()]
            for _, row in yr_data.iterrows():
                result[str(row['TEAM']).strip().lower()] = {
                    'OVR': row.get('OVR', row.get('OVERALL')),
                    'OFF': row.get('OFF', row.get('OFFENSE')),
                    'DEF': row.get('DEF', row.get('DEFENSE')),
                }
        return result
    except Exception:
        return {}


@st.cache_data(ttl=300)
def compute_conf_standings_from_schedule(year=None, write_csv=True):
    """
    Derive conf_standings_{YEAR}.csv from schedule_{YEAR}.csv (or CPUscores fallback).

    Computes per-team: W, L, PF, PA, DIFF, MOV, HOME (W-L string), AWAY (W-L string),
    STK (signed int: +3=W3, -2=L2), CONF_W, CONF_L, and CONFERENCE (from
    team_conferences.csv if available).

    Returns a DataFrame in the same schema as conf_standings_{YEAR}.csv so all
    existing callers (load_team_performance, Who's In, SOS, FPI) work unchanged.
    Also writes the CSV to disk if write_csv=True so the watcher-imported file
    is no longer strictly required.
    """
    target_year = int(year) if year else CURRENT_YEAR
    df = load_scores_master(target_year)
    if df.empty:
        return pd.DataFrame()

    # Only completed games
    df = df.copy()
    df['YEAR'] = pd.to_numeric(df.get('YEAR', target_year), errors='coerce')
    df['Week'] = pd.to_numeric(df.get('Week', 0), errors='coerce')
    df = df[df['YEAR'].fillna(-1).astype(int) == target_year]
    completed = df[df.get('Status', pd.Series(['FINAL']*len(df))).astype(str).str.upper() == 'FINAL'].copy()
    if completed.empty:
        return pd.DataFrame()

    # Coerce scores
    for col in ('Vis Score', 'Home Score'):
        completed[col] = pd.to_numeric(completed.get(col, 0), errors='coerce').fillna(0)

    # Load conference map from team_conferences.csv
    conf_map = {}
    try:
        _tc = pd.read_csv('team_conferences.csv')
        _tc['TEAM'] = _tc['TEAM'].astype(str).str.strip()
        _tc['CONFERENCE'] = _tc['CONFERENCE'].astype(str).str.strip()
        conf_map = dict(zip(_tc['TEAM'], _tc['CONFERENCE']))
    except Exception:
        pass

    # Build per-team stats
    stats = {}  # team → running totals dict

    def _get(team):
        if team not in stats:
            stats[team] = {
                'W': 0, 'L': 0, 'PF': 0.0, 'PA': 0.0,
                'HOME_W': 0, 'HOME_L': 0, 'AWAY_W': 0, 'AWAY_L': 0,
                'CONF_W': 0, 'CONF_L': 0,
                'results': [],  # ordered list of 'W'/'L' for streak calc
            }
        return stats[team]

    for _, g in completed.iterrows():
        vis  = str(g.get('Visitor', '')).strip()
        hom  = str(g.get('Home',    '')).strip()
        vpts = float(g.get('Vis Score',  0) or 0)
        hpts = float(g.get('Home Score', 0) or 0)
        if not vis or not hom:
            continue

        v_won = vpts > hpts
        is_conf = (conf_map.get(vis) and conf_map.get(hom) and
                   conf_map.get(vis) == conf_map.get(hom))

        # Visitor record
        sv = _get(vis)
        sv['PF'] += vpts; sv['PA'] += hpts
        sv['AWAY_W' if v_won else 'AWAY_L'] += 1
        sv['W' if v_won else 'L'] += 1
        if is_conf: sv['CONF_W' if v_won else 'CONF_L'] += 1
        sv['results'].append('W' if v_won else 'L')

        # Home record
        sh = _get(hom)
        sh['PF'] += hpts; sh['PA'] += vpts
        sh['HOME_W' if not v_won else 'HOME_L'] += 1
        sh['W' if not v_won else 'L'] += 1
        if is_conf: sh['CONF_W' if not v_won else 'CONF_L'] += 1
        sh['results'].append('W' if not v_won else 'L')

    if not stats:
        return pd.DataFrame()

    rows = []
    for team, s in sorted(stats.items()):
        gp   = max(s['W'] + s['L'], 1)
        diff = s['PF'] - s['PA']
        mov  = round(diff / gp, 2)

        # Streak: walk results backwards
        streak_sign = s['results'][-1] if s['results'] else 'W'
        streak_count = 0
        for r in reversed(s['results']):
            if r == streak_sign:
                streak_count += 1
            else:
                break
        stk = streak_count if streak_sign == 'W' else -streak_count

        rows.append({
            'YEAR':       target_year,
            'TEAM':       team,
            'CONFERENCE': conf_map.get(team, ''),
            'W':          s['W'],
            'L':          s['L'],
            'CONF_W':     s['CONF_W'],
            'CONF_L':     s['CONF_L'],
            'PF':         round(s['PF'], 1),
            'PA':         round(s['PA'], 1),
            'DIFF':       round(diff, 1),
            'MOV':        mov,
            'HOME':       f"{s['HOME_W']}-{s['HOME_L']}",
            'AWAY':       f"{s['AWAY_W']}-{s['AWAY_L']}",
            'STK':        stk,
        })

    out = pd.DataFrame(rows)

    # Compute conf rank within each conference by conf W-L then overall W-L
    if not out.empty:
        out = out.sort_values(['CONFERENCE', 'CONF_W', 'W'], ascending=[True, False, False])
        out['CONF_RANK'] = out.groupby('CONFERENCE').cumcount() + 1
        out = out.sort_values(['W', 'DIFF'], ascending=False).reset_index(drop=True)

    if write_csv and not out.empty:
        try:
            out.to_csv(f'conf_standings_{target_year}.csv', index=False)
        except Exception:
            pass

    return out


