        def _hh_safe_num(v, default=0.0):
            try:
                if pd.isna(v):
                    return default
                return float(v)
            except Exception:
                return default

        def _hh_safe_int(v, default=0):
            try:
                if pd.isna(v):
                    return default
                return int(float(v))
            except Exception:
                return default

        def _headline_history_load():
            cols = [
                'season','week','headline_id','event_type','team','player','headline_text',
                'score','shown_rank','uniqueness_key','story_group','tone','arc_stage'
            ]
            try:
                if _headline_history_path.exists():
                    _hh = pd.read_csv(_headline_history_path)
                    for _c in cols:
                        if _c not in _hh.columns:
                            _hh[_c] = ''
                    return _hh[cols].copy()
            except Exception:
                pass
            return pd.DataFrame(columns=cols)

        def _headline_history_save(_rows):
            try:
                _hh_existing = _headline_history_load()
                _hh_new = pd.DataFrame(_rows)
                if _hh_new.empty:
                    return
                for _c in _hh_existing.columns:
                    if _c not in _hh_new.columns:
                        _hh_new[_c] = ''
                _hh_new = _hh_new[_hh_existing.columns].copy()
                _hh_all = pd.concat([_hh_existing, _hh_new], ignore_index=True)
                _hh_all = _hh_all.drop_duplicates(subset=['season','week','uniqueness_key'], keep='last')
                _hh_all.to_csv(_headline_history_path, index=False)
            except Exception:
                pass

