    st.subheader("🕰️ Coach Recruiting History")
    st.caption(f"Class ranks by coach and school over time. Data from recruiting.csv — year columns (e.g. 2039, 2040, 2041) must be populated there for each season. Current year {CURRENT_YEAR} class won't appear until you enter it.")

    _history_year_cols = []
    if rec is not None and not rec.empty:
        for c in rec.columns:
            try:
                _yr_int = int(float(str(c)))
                if 2000 <= _yr_int <= 2100:   # sanity range for a CFB dynasty year
                    _history_year_cols.append(c)
            except Exception:
                pass
    if _history_year_cols:
        _history_year_cols = sorted(_history_year_cols, key=lambda x: int(float(str(x))))
        _rec_hist = rec.copy()
        _rec_hist['USER'] = _rec_hist['USER'].astype(str).str.strip().str.title()
        _rec_hist['Teams'] = _rec_hist['Teams'].astype(str).str.strip().map(normalize_history_team_name)

        _history_users = sorted(_user_teams_map.keys())
        _hist_user = st.selectbox(
            "Choose a coach",
            _history_users,
            key="coach_recruiting_history_user"
        )

        _coach_rows = _rec_hist[_rec_hist['USER'] == _hist_user].copy()
        if _coach_rows.empty:
            st.caption("No recruiting history found for that coach in recruiting.csv.")
        else:
            _school_cards = []
            for _, _hr in _coach_rows.iterrows():
                _hist_team = str(_hr.get('Teams', '')).strip()
                if not _hist_team or _hist_team.lower() == 'nan':
                    continue

                _year_vals = []
                for _yc in _history_year_cols:
                    _v = _hr.get(_yc)
                    if pd.notna(_v) and str(_v).strip() not in ('', 'nan', '-', '--'):
                        try:
                            _rank_val = int(float(_v))
                            _yr_int   = int(float(str(_yc)))
                            _year_vals.append({'Year': _yr_int, 'Class Rank': _rank_val})
                        except Exception:
                            pass

                if not _year_vals:
                    continue

                _hist_df = pd.DataFrame(_year_vals).sort_values('Year', ascending=False).reset_index(drop=True)
                _best_rank = int(_hist_df['Class Rank'].min())
                _latest_rank = int(_hist_df.iloc[0]['Class Rank'])
                _years_span = sorted(_hist_df['Year'].astype(int).tolist())

                if len(_years_span) == 1:
                    _years_label = str(_years_span[0])
                else:
                    _years_label = f"{_years_span[0]}–{_years_span[-1]}"

                _school_cards.append({
                    'team': _hist_team,
                    'df': _hist_df,
                    'best_rank': _best_rank,
                    'latest_rank': _latest_rank,
                    'years_label': _years_label,
                    'classes': len(_hist_df),
                })

            if not _school_cards:
                st.caption("No historical class ranks found for that coach.")
            else:
                _school_cards = sorted(_school_cards, key=lambda x: x['df']['Year'].min())

                st.markdown(f"#### {_hist_user}'s class-by-class results")

                for _card in _school_cards:
                    _cl_team   = _card['team']
                    _cl_logo_uri = image_file_to_data_uri(get_logo_source(_cl_team))
                    _cl_primary  = get_team_primary_color(_cl_team)
                    _cl_logo_html = f"<img src='{_cl_logo_uri}' style='width:22px;height:22px;object-fit:contain;vertical-align:middle;margin-right:7px;'/>" if _cl_logo_uri else ""
                    _cl_label = (
                        f"{_cl_team} — "
                        f"Best #{_card['best_rank']} · "
                        f"Latest #{_card['latest_rank']} · "
                        f"{_card['years_label']} · "
                        f"{_card['classes']} class{'es' if _card['classes'] != 1 else ''}"
                    )
                    # Color the best rank green if top 10, gold if top 25
                    _best_color = '#4ade80' if _card['best_rank'] <= 10 else ('#fbbf24' if _card['best_rank'] <= 25 else '#94a3b8')
                    with st.expander(_cl_label, expanded=False):
                        st.markdown(
                            f"<div style='display:flex;align-items:center;gap:8px;margin-bottom:10px;'>"
                            f"{_cl_logo_html}"
                            f"<span style='font-family:Barlow Condensed,sans-serif;font-weight:800;font-size:1.05rem;color:{_cl_primary};'>{html.escape(_cl_team)}</span>"
                            f"<span style='font-size:0.72rem;color:#475569;'>{_card['years_label']}</span>"
                            f"</div>",
                            unsafe_allow_html=True
                        )
                        # Render year-by-year table with color coded ranks
                        _yr_rows = []
                        for _, _yr_row in _card['df'].iterrows():
                            _rk = int(_yr_row['Class Rank'])
                            _rk_color = '#4ade80' if _rk <= 10 else ('#fbbf24' if _rk <= 25 else ('#60a5fa' if _rk <= 50 else '#94a3b8'))
                            _yr_rows.append(
                                f"<tr><td style='padding:6px 12px;color:#94a3b8;'>{int(_yr_row['Year'])}</td>"
                                f"<td style='padding:6px 12px;font-weight:800;color:{_rk_color};font-family:Bebas Neue,sans-serif;font-size:1.1rem;'>#{_rk}</td>"
                                f"<td style='padding:6px 12px;'>"
                                + ("🔥" if _rk <= 5 else ("⭐" if _rk <= 10 else ("📈" if _rk <= 25 else "")))
                                + "</td></tr>"
                            )
                        st.markdown(
                            f"<table style='width:100%;border-collapse:collapse;background:#080f1a;border-radius:6px;overflow:hidden;'>"
                            f"<thead><tr style='background:#0a1220;'>"
                            f"<th style='padding:6px 12px;color:#475569;font-size:0.65rem;text-align:left;'>Year</th>"
                            f"<th style='padding:6px 12px;color:#475569;font-size:0.65rem;text-align:left;'>Class Rank</th>"
                            f"<th style='padding:6px 12px;'></th>"
                            f"</tr></thead><tbody>{''.join(_yr_rows)}</tbody></table>",
                            unsafe_allow_html=True
                        )
    else:
        st.caption("No recruiting history columns were found in recruiting.csv.")

